/* techniques q12 (69 mục) — R6 sửa lỗi - gop trung 2026-07-13 - gop trung 2026-07-14 - gop trung 2026-07-15 - gop trung 2026-07-15 - gop trung 2026-07-15 - gop trung 2026-07-16 - gop trung 2026-07-16 */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q12"]=window.__LIBQ["tien-nghich"]["q12"]||{};window.__LIBQ["tien-nghich"]["q12"]["techniques"]={"updatedAt":"2026-07-13","count":69,"techniques":[{"id":"chu-tuoc-sam-la-viem","name":"Chu Tước Sâm La Viêm","cn":"朱雀参罗焱","aliases":["Sâm La Viêm","Sâm La Hỏa"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Chu Tước tộc","soHuu":["Điên Lạc đại đế"],"blurb":"Chu Tước Sâm La Viêm là tâm thần hỏa của Lão Tổ Chu Tước đời đầu tiên, có nguồn gốc từ thời đại cổ xưa. Ngọn lửa biến chuyển chín lần mỗi nhịp thở giữa thực chất và hư ảo, uy lực tăng điên cuồng, ba nhịp thở đủ thiêu tro hồn phách thường. Được lão tổ sử dụng trong Thiên Phương giới để thí luyện luyện hồn cho hậu bối.","detail":"Chu Tước Sâm La Viêm là tâm thần hỏa thuộc về Lão Tổ Chu Tước đời đầu tiên, tồn tại từ thời đại cổ xưa. Khác với hư hỏa thông thường, ngọn lửa này không ngừng biến đổi giữa thực chất và hư ảo, mỗi nhịp thở biến chuyển chín lần, uy lực theo đó tăng trưởng điên cuồng. Chỉ trong ba nhịp thở, Sâm La Viêm đã có thể thiêu tro hồn phách bình thường; khi vượt qua giới hạn, ngọn lửa từ chín màu chuyển hóa thành hỗn độn. Tại Thiên Phương giới, Lão Tổ Chu Tước đời đầu đã dùng Sâm La Viêm thiêu đốt Vương Lâm, bề ngoài là thí luyện nhưng thực chất nhằm mục đích luyện hồn cho hậu bối.","thuocTinh":"Hỏa","nguonGoc":"Tâm thần hỏa của Lão Tổ Chu Tước đời đầu tiên, thời đại cổ xưa","uyLuc":"Mỗi nhịp thở biến chuyển chín lần, uy lực tăng điên cuồng; ba nhịp thở có thể thiêu tro hồn phách thường; khi vượt giới hạn, lửa chuyển hóa thành hỗn độn.","dacDiem":"Không phải hư hỏa, ngọn lửa không ngừng biến đổi giữa thực chất và hư ảo, mỗi nhịp thở biến chuyển chín lần.","congNang":["Thiêu đốt hồn phách, ba nhịp thở đủ thiêu tro hồn phách thường @c1325","Luyện hồn cho hậu bối thông qua thí luyện @c1325"],"nguoiTu":[{"ten":"Điên Lạc đại đế","tuChuong":"@c1325","tangDatToi":"Không rõ","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1325","loai":"xuat-hien","importance":"major","giaiDoan":"Lần đầu xuất hiện","text":"Lão tổ Chu Tước đời đầu dùng Sâm La Viêm thiêu đốt Vương Lâm trong Thiên Phương giới như thí luyện luyện hồn. Ngọn lửa biến đổi chín lần giữa thực chất và hư ảo, mỗi nhịp thở uy lực tăng điên cuồng.","anchor":"Đây không phải là hư hỏa mà là tâm thần hỏa của bổn tước. Trong thời đại của bổn tước, thứ lửa này được gọi là Chu Tước Sâm La Viêm"}]},"nguon":["@c1325"]},{"id":"co-loi-gioi","name":"Cổ Lôi Giới","cn":"古雷界","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Lôi","soHuu":["Vương Lâm"],"blurb":"Cổ Lôi Giới là thần thông của đại trưởng lão Thiểm Lôi tộc, dùng lôi đỉnh ngưng tụ vạn đạo lôi đồ, xé khe không gian ngàn trượng triệu hoán thái cổ Lôi Long. Vương Lâm nhờ thuật sưu hồn kết hợp lôi đình bổn nguyên đại thành mà thi triển được, lần đầu sử dụng trong thí luyện Thiên phương giới nhưng bị Chu Tước đời đầu dùng Chu Tước ấn phong bế hoàn toàn.","detail":"Cổ Lôi Giới vốn là thần thông của đại trưởng lão Thiểm Lôi tộc, đòi hỏi lôi đình bổn nguyên đạt mức đại thành mới đủ cơ sở thi triển. Vương Lâm có được chiêu thức này thông qua thuật sưu hồn, kết hợp với nền tảng lôi đình bổn nguyên của bản thân. Khi kích phát, lôi đỉnh ngưng tụ vạn đạo lôi đồ, xé rách khe không gian rộng tới ngàn trượng, mở ra cổ giới để triệu hoán thái cổ Lôi Long giáng thế. Lần đầu tiên Vương Lâm sử dụng Cổ Lôi Giới diễn ra trong thí luyện tại Thiên phương giới, khe không gian ngàn trượng mở thành công và thái cổ Lôi Long xuất hiện, tuy nhiên Chu Tước đời đầu đã dùng Chu Tước ấn phong bế hoàn toàn, khiến chiêu thức không phát huy trọn vẹn uy lực.","nguonGoc":"Thần thông của đại trưởng lão Thiểm Lôi tộc","congNang":["Mở khe không gian ngàn trượng triệu hoán thái cổ Lôi Long @c1326"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1326","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1326","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Vương Lâm lần đầu mở Cổ Lôi Giới trong thí luyện Thiên phương giới, xé khe không gian ngàn trượng triệu hoán thái cổ Lôi Long, nhưng bị Chu Tước đời đầu dùng Chu Tước ấn phong bế hoàn toàn.","anchor":"lấy danh nghĩa lôi đỉnh của ta, ngưng tụ vạn đạo lôi đồ, mở ra cổ lôi giới"}]},"nguon":["@c1326"]},{"id":"con-duong-nam-bon-nguyen","name":"Con đường năm đạo bổn nguyên","cn":"","loai":"cong-phap","loaiLabel":"Công pháp","phamCap":"Chưa rõ","hePhai":"Tự ngộ","soHuu":["Vương Lâm"],"blurb":"Con đường năm đạo bổn nguyên là con đường thành đạo do Vương Lâm tự ngộ, chưa từng có tiền lệ. Năm đạo bổn nguyên tương đương thiên nhân ngũ suy và phá không ngũ chỉ; khi cả năm đều đại thành, sẽ phá không môn mà thành đạo của riêng mình.","detail":"Tại chương @c1327, Vương Lâm từ chối đề xuất của Chu Tước đời đầu tiên và tự ngộ ra con đường tu hành độc nhất: năm đạo bổn nguyên của hắn chính là năm ngón tay, tương ứng với thiên nhân ngũ suy cùng phá không ngũ chỉ. Đây là con đường chưa ai từng đi — khi năm bổn nguyên đều đạt đại thành, hắn sẽ trở thành tu sĩ thiên nhân ngũ suy viên mãn, có thể đánh tan không môn và thành tựu đạo của riêng mình.","congNang":["Năm bổn nguyên đại thành tương đương thiên nhân ngũ suy viên mãn @c1327","Phá không môn thành đạo khi năm bổn nguyên đều đại thành @c1327"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1327","tangDatToi":"Mới ngộ, chưa đại thành","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1327","loai":"xuất hiện","importance":"major","giaiDoan":"Tự ngộ","text":"Vương Lâm từ chối đề xuất của Chu Tước đời đầu tiên, tự ngộ ra con đường riêng: năm đạo bổn nguyên chính là năm ngón tay, tương đương thiên nhân ngũ suy và phá không ngũ chỉ. Khi đại thành sẽ phá không môn thành đạo.","anchor":"năm ngón tay của vãn bối chính là năm đạo bổn nguyên"}]},"nguon":["@c1327"],"dacDiem":"Con đường thành đạo do Vương Lâm tự ngộ, chưa từng có tiền lệ; năm đạo bổn nguyên ứng với năm ngón tay, tương đương thiên nhân ngũ suy và phá không ngũ chỉ."},{"id":"ngung-tu-hu-hoa-ben-ngoai","name":"Ngưng tụ hư hỏa bên ngoài","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Hư hỏa (Chu Tước huyết mạch)","soHuu":["Vương Lâm"],"blurb":"Thần thông hư hỏa mới của Vương Lâm sau khi thức tỉnh Chu Tước huyết mạch lần thứ tư và hoàn thành thí luyện Thiên phương hương, cho phép hút hư hỏa từ cơ thể tu sĩ khác về mình tạo cơn lốc hư hỏa khổng lồ bao phủ thiên địa.","detail":"Sau khi trải qua thí luyện Thiên phương hương và thức tỉnh Chu Tước huyết mạch lần thứ tư, Vương Lâm lĩnh ngộ được năng lực ngưng tụ hư hỏa bên ngoài. Khi thi triển, Vương Lâm vung tay khiến hư hỏa xuất hiện trên thân thể mấy vạn tu sĩ bốn phía rồi hút toàn bộ về mình, hóa thành cơn lốc hư hỏa cuộn tới tận trời cao. Lấy Vương Lâm làm trung tâm, lực xoáy mãnh liệt đẩy tu sĩ bốn phía ra ngoài nghìn trượng. Lão Chu Tước chứng kiến cũng phải trợn mắt kinh hãi, nhận ra đây chính là ngưng tụ hư hỏa bên ngoài — một năng lực tác động diện rộng cực kỳ hiếm thấy. @c1328","thuocTinh":"Hỏa (hư hỏa)","nguonGoc":"Thức tỉnh sau thí luyện Thiên phương hương và thức tỉnh Chu Tước huyết mạch lần thứ tư","uyLuc":"Hút hư hỏa từ cơ thể mấy vạn tu sĩ cùng lúc, tạo cơn lốc hư hỏa bao phủ thiên địa, lực xoáy đẩy người ra ngoài nghìn trượng, khiến ngay cả Lão Chu Tước cũng phải kinh hãi.","dacDiem":"Năng lực tác động diện rộng, lấy bản thân làm trung tâm; không tự sinh hư hỏa mà cưỡng chế hút hư hỏa từ cơ thể tu sĩ xung quanh để ngưng tụ thành sức mạnh của mình.","congNang":["Hút hư hỏa từ cơ thể tu sĩ khác về bản thân, phạm vi lên tới mấy vạn người @c1328","Tạo cơn lốc hư hỏa khổng lồ cuộn quanh thân, vươn tới tận trời cao @c1328","Lực xoáy lấy bản thân làm trung tâm đẩy tu sĩ bốn phía ra ngoài nghìn trượng @c1328"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1328","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1328","loai":"xuat-hien","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Vương Lâm vung tay hút hư hỏa từ cơ thể mấy vạn tu sĩ bốn phía, hóa thành cơn lốc hư hỏa khổng lồ cuộn quanh thân, Lão Chu Tước kinh hãi xác nhận đây là ngưng tụ hư hỏa bên ngoài.","anchor":"Đây là. ngưng tụ hư hỏa bên ngoài!"}]},"nguon":["@c1328"]},{"id":"pha-khong-cuu-diet","name":"Phá Không Cửu Diệt","cn":"破空九灭","aliases":["Cửu bộ diệt thiên"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đại thần thông bước thứ ba","hePhai":"","soHuu":["Tư Mặc Tử"],"blurb":"Phá Không Cửu Diệt là đại thần thông bước thứ ba của Ti Mặc Tử, thi triển chín bước chín dạng hủy diệt khác nhau rồi hợp nhất thành chưởng cửu bộ diệt thiên mang sức mạnh phá thiên. Chiêu thức này đã được Ti Mặc Tử tuần tự triển khai đủ chín bước khi đối đầu Vương Lâm trên Đại Đế tinh.","detail":"Phá Không Cửu Diệt là thần thông thuộc hệ thống đại thần thông bước thứ ba của Ti Mặc Tử. Khi thi triển, người dùng tuần tự bước chín bước, mỗi bước kích hoạt một dạng hủy diệt riêng biệt: nhất diệt thiên — xé bầu trời thành vết nứt; nhị diệt địa — ngọn núi rẽ đất mọc lên; tam diệt sinh — gió lạnh thổi tắt sức sống; tứ diệt táng vong — mộ hư ảo tràn ngập tử khí; ngũ diệt thì quang — tuế nguyệt lưu chuyển; lục diệt hư vô — màn hư vô bao trùm; thất diệt hồng hoang — khí tức tang thương lan tỏa; bát diệt luân hồi; cửu diệt phá thiên. Sau khi đủ chín bước, toàn bộ hư ảnh của chín diệt hóa thành dòng sông mảnh nhỏ hội tụ vào tay phải, hợp nhất thành chưởng cửu bộ diệt thiên. Ti Mặc Tử đã tuần tự thi triển đủ chín bước chín diệt trong trận đối đầu với Vương Lâm trên Đại Đế tinh (@c1329).","congNang":["Nhất diệt thiên: xé bầu trời thành vết nứt (@c1329)","Nhị diệt địa: ngọn núi rẽ đất mọc lên (@c1329)","Tam diệt sinh: gió lạnh thổi tắt sức sống (@c1329)","Tứ diệt táng vong: mộ hư ảo tràn ngập tử khí (@c1329)","Ngũ diệt thì quang: tuế nguyệt lưu chuyển (@c1329)","Lục diệt hư vô: màn hư vô bao trùm (@c1329)","Thất diệt hồng hoang: khí tức tang thương lan tỏa (@c1329)","Bát diệt luân hồi (@c1329)","Cửu diệt phá thiên — chín bước hợp nhất, toàn bộ hư ảnh hóa thành dòng sông mảnh nhỏ hội tụ vào tay phải, hợp nhất thành chưởng cửu bộ diệt thiên (@c1329)"],"nguoiTu":[{"ten":"Tư Mặc Tử","tuChuong":"@c1329","tangDatToi":"Cửu diệt đầy đủ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1329","loai":"thi triển","importance":"major","giaiDoan":"Thi triển đầy đủ chín diệt","text":"Ti Mặc Tử tuần tự thi triển đủ chín bước chín diệt đối đầu Vương Lâm trên Đại Đế tinh, hợp nhất thành chưởng cửu bộ diệt thiên. Chưởng Phá Thiên va chạm với cửu sắc hư hỏa của Vương Lâm, không dập tắt được ngọn lửa.","anchor":"Phá không cửu diệt, cửu bộ diệt thiên"}]},"dinhDanh":"goc","cacTang":[{"ten":"Nhất diệt thiên","moTa":"Xé bầu trời thành vết nứt","chuong":"@c1329"},{"ten":"Nhị diệt địa","moTa":"Mặt đất rung chuyển, ngọn núi rẽ đất mọc lên","chuong":"@c1329"},{"ten":"Tam diệt sinh","moTa":"Gió lạnh thổi tắt sức sống","chuong":"@c1329"},{"ten":"Tứ diệt táng vong","moTa":"Hư ảo ngôi mộ, tử khí","chuong":"@c1329"},{"ten":"Ngũ diệt thì quang","moTa":"Tuế nguyệt lưu chuyển","chuong":"@c1329"},{"ten":"Lục diệt hư vô","moTa":"Màn hư vô","chuong":"@c1329"},{"ten":"Thất diệt hồng hoang","moTa":"Khí tức tang thương","chuong":"@c1329"},{"ten":"Bát diệt luân hồi","moTa":"Luân hồi","chuong":"@c1329"},{"ten":"Cửu diệt phá thiên","moTa":"Phá thiên — hợp nhất toàn bộ thành chưởng","chuong":"@c1329"}],"nguon":["@c1329"],"uyLuc":"Chín bước chín diệt hợp nhất thành chưởng cửu bộ diệt thiên mang sức mạnh phá thiên, được Ti Mặc Tử thi triển đầy đủ trong trận đối đầu Vương Lâm trên Đại Đế tinh (@c1329).","dacDiem":"Thần thông theo dạng tích lũy tuần tự — mỗi bước triển khai một dạng hủy diệt riêng biệt bao quát thiên, địa, sinh, tử, thời gian, hư vô, hồng hoang, luân hồi, sau cùng toàn bộ hư ảnh quy về một chưởng duy nhất mang lực phá thiên."},{"id":"huong-hoa-than-thong","name":"Hương hỏa thần thông","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Bước thứ ba","hePhai":"","soHuu":["Tư Mặc Tử"],"blurb":"Hương hỏa thần thông là thần thông chỉ thuộc về bước thứ ba, cho phép người sử dụng xé không gian mở hương hỏa giới, triệu hồi vô tận hồn phách hương hỏa hư ảo. Hồn phách vái một vái tạo cuồng phong tím mang quy tắc bước thứ ba, có thể dùng để dập tắt hỏa diễm trên chính thân hoặc áp bức đối thủ.","detail":"Tư Mặc Tử thi triển thần thông này bằng cách xé không gian mở ra hương hỏa giới — một giới riêng do hắn luyện hóa, bên trong chứa vô số tu chân tinh với sinh linh quỳ lạy cúng bái, cung cấp lực hương hỏa. Từ hương hỏa giới, hắn triệu ra vô tận hồn phách hương hỏa hư ảo. Khi hồn phách vái mục tiêu một vái sẽ sinh ra cuồng phong tím mang theo quy tắc bước thứ ba: vái chính thân thì dập tắt toàn bộ hư hỏa, vái đối thủ thì áp bức khiến đối phương đau đớn tới mức chưa đạt bước thứ ba không thể chịu nổi. Tuy nhiên, hồn phách hao tổn rất lớn sau mỗi lần sử dụng.","congNang":["Xé không gian mở hương hỏa giới, triệu hồi vô tận hồn phách hương hỏa hư ảo @c1330","Hồn phách vái chính thân tạo cuồng phong tím mang quy tắc bước thứ ba, dập tắt toàn bộ hư hỏa trên thân @c1330","Hồn phách vái đối thủ tạo cuồng phong tím mang quy tắc bước thứ ba, áp bức đối phương đau đớn — chưa đạt bước thứ ba không thể chịu nổi"],"nguoiTu":[{"ten":"Tư Mặc Tử","tuChuong":"@c1330","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1330","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Tư Mặc Tử xé không gian mở hương hỏa giới, triệu vô tận hồn phách hương hỏa. Hồn phách vái một cái dập tắt toàn bộ hư hỏa trên người hắn. Sau đó sai hồn phách vái Vương Lâm, cuồng phong tím kèm quy tắc bước thứ ba áp bức đối thủ đau đớn gần xé thân.","anchor":"Hương hỏa thần thông! Đây là thần thông chỉ thuộc về bước thứ ba"}]},"nguon":["@c1330"],"uyLuc":"Cuồng phong tím mang quy tắc bước thứ ba khiến đối thủ chưa đạt bước thứ ba không thể chịu nổi sức áp bức.","dacDiem":"Thần thông chỉ thi triển được ở bước thứ ba, dựa vào hương hỏa giới riêng chứa vô số sinh linh cúng bái làm nguồn lực; hồn phách hao tổn lớn sau mỗi lần sử dụng."},{"id":"tu-dao","name":"Tử Đạo","cn":"死道","loai":"than-thong","loaiLabel":"Đạo bổn nguyên","phamCap":"Đạo bổn nguyên (một trong bảy màu)","hePhai":"Chưởng Tôn","soHuu":["Tư Mặc Tử"],"blurb":"Tử Đạo là một trong bảy màu đạo bổn nguyên của Chưởng Tôn, được ban thưởng cho Tư Mặc Tử vì lập nhiều công lao. Biểu hiện dưới dạng sương tím, lấy đau đớn làm khởi đầu, khiến mọi linh hồn phát điên dưới uy lực của nó.","detail":"Tử Đạo thuộc hệ thống bảy màu đạo bổn nguyên của Chưởng Tôn đại nhân, mang sắc tím. Tư Mặc Tử nhờ lập nhiều công lao mà được Chưởng Tôn ban cho đạo này. Khi thi triển, Tư Mặc Tử tay phải nắm hết màu tím trời đất quét ngang, sương tím lan tràn khắp nơi, tấn công trực tiếp vào linh hồn đối phương khiến chúng chìm trong đau đớn và phát điên. Tại chương 1331, Tư Mặc Tử dùng Tử Đạo đối chiến Cổ Ma Hồn của Vương Lâm; tuy nhiên Cổ Ma Hồn — thân là Cổ Ma đứng đầu ma trong trời đất — hoàn toàn miễn nhiễm trước sương tím, ngược lại còn hưng phấn và chủ động nuốt lấy sương tím.","thuocTinh":"Tử (tím)","nguonGoc":"Chưởng Tôn đại nhân ban thưởng cho Tư Mặc Tử vì lập nhiều công lao","uyLuc":"Lấy đau đớn làm khởi đầu, khiến mọi linh hồn phát điên dưới Tử Đạo; tuy nhiên Cổ Ma Hồn — Cổ Ma đứng đầu ma trong trời đất — miễn nhiễm và ngược lại chủ động nuốt sương tím.","dacDiem":"Một trong bảy màu đạo bổn nguyên của Chưởng Tôn, biểu hiện dưới dạng sương tím lan tràn khi thi triển.","congNang":["Lấy đau đớn làm khởi đầu, khiến mọi linh hồn phát điên @c1331"],"nguoiTu":[{"ten":"Tư Mặc Tử","tuChuong":"@c1331","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1331","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Tư Mặc Tử thi triển Tử Đạo đối chiến Cổ Ma Hồn của Vương Lâm, sương tím lan tràn nhưng Cổ Ma Hồn miễn nhiễm, ngược lại nuốt sương tím ma tính càng dày.","anchor":"Tử đạo này một khi xuất ra, lấy đau đớn làm khởi đầu"}]},"capNhatToi":"@c1331","dinhDanh":"goc","nguon":["@c1331"]},{"id":"suc-manh-tue-nguyet","name":"Sức mạnh tuế nguyệt","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Tiểu Lan"],"blurb":"Sức mạnh tuế nguyệt do nữ tử lụa trắng thi triển, giơ tay ấn ra phóng luồng lực lượng bao vây mục tiêu, vặn vẹo không gian phía trước.","detail":"Nữ tử từ đám sương đỏ giơ tay ấn ra, phóng sức mạnh tuế nguyệt bao vây Cổ Ma Hồn, vặn vẹo không gian phía trước.","congNang":["Phóng sức mạnh tuế nguyệt bao vây mục tiêu, vặn vẹo không gian"],"tabs":{"tienTrinh":[{"chuong":"@c1332","loai":"thi triển","importance":"normal","giaiDoan":"Xuất hiện lần đầu","text":"Nữ tử lụa trắng giơ tay ấn ra phóng sức mạnh tuế nguyệt bao vây Cổ Ma Hồn trong trận chiến với Vương Lâm.","anchor":"Một luồng sức mạnh tuế nguyệt trong tiếng ầm ầm từ trong tay của nữ tử này tràn ra"}]},"nguoiTu":[{"ten":"Tiểu Lan","tuChuong":"@c1332","tangDatToi":"","trangThai":"dang-tu"}],"nguon":["@c1332"]},{"id":"nguyet-luu","name":"Nguyệt Lưu","loai":"than-thong","loaiLabel":"Thần thông","soHuu":["Vương Lâm"],"blurb":"Thức thần thông thứ hai do Vương Lâm sáng tạo, mang quy tắc Tuế Nguyệt, bao trùm vạn vật, không ai phòng ngự nổi, sánh với thiên đạo.","detail":"Quy tắc Tuế Nguyệt, trong thiên địa không có bất cứ kẻ nào có thể phòng ngự và chống cự nổi. Sức mạnh bao trùm vạn vật, sánh ngang thiên đạo.","dacDiem":"Quy tắc Tuế Nguyệt, so sánh với thiên đạo, không ai phòng ngự nổi","congNang":["Quy tắc Tuế Nguyệt bao trùm vạn vật, không thể phòng ngự"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1333","tangDatToi":"Không rõ","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1333","loai":"nhac-toi","importance":"normal","giaiDoan":"Được hồi tưởng trong hệ thống ba thức","text":"Được nhắc lại là thức thần thông thứ hai của Vương Lâm, mang quy tắc Tuế Nguyệt, không ai phòng ngự nổi, sánh với thiên đạo.","anchor":"thuật này lại có quy tắc Tuế Nguyệt, trong thiên địa không có bất cứ kẻ nào có thể phòng ngự và chống cự nổi"}]},"capNhatToi":"@c1333","nguon":["@c1333"]},{"id":"mong-ve-vien-co","name":"Mộng Về Viễn Cổ","loai":"than-thong","loaiLabel":"Thần thông bảo mệnh bát tinh Cổ Thần","soHuu":[],"blurb":"Thần thông bảo mệnh bát tinh Cổ Thần, uy lực kinh người nhưng tu sĩ không có khả năng thi triển. Là một phần nguyên liệu để Vương Lâm sáng chế Mộng Đạo thuật.","detail":"Vương Lâm thi triển lần đầu khi gặp Thiên Vân Tử tại vùng đất Yêu Linh. Trong Đạo Cảnh nhận ra tu sĩ không thể thi triển dù là Cổ Thần. Kết hợp cùng Tán Đạo thành nguyên liệu cho Mộng Đạo thuật.","dacDiem":"Tu sĩ không có khả năng thi triển, thần thông tiếp cận đạo thuật","congNang":["Thần thông bảo mệnh cực mạnh của bát tinh Cổ Thần"],"tabs":{"tienTrinh":[{"chuong":"@c1333","loai":"nhac-toi","importance":"normal","giaiDoan":"Được nhắc lại như nguyên liệu Mộng Đạo","text":"Được nhắc trong hồi tưởng: Vương Lâm thi triển lần đầu khi gặp Thiên Vân Tử tại Yêu Linh, ở Đạo Cảnh nhận ra tu sĩ không thể thi triển, là nguyên liệu sáng chế Mộng Đạo thuật.","anchor":"thần thông có uy lực kinh người như Mộng Về Viễn Cổ của Cổ Thần vốn tu sĩ không có khả năng thi triển"}]},"capNhatToi":"@c1333","nguon":["@c1333"]},{"id":"tan-dao","name":"Tán Đạo","loai":"than-thong","loaiLabel":"Đạo thuật / Thần thông","soHuu":["Lão giả Phong diệt tộc"],"blurb":"Đạo thuật do lão giả Phong diệt tộc thi triển trong Phong giới năm xưa, mở ra cánh cửa đạo thuật mới cho Vương Lâm, là nguyên liệu sáng chế Mộng Đạo thuật.","detail":"Tán Đạo được lão giả Phong diệt tộc thi triển trong Phong giới. Vương Lâm mượn Đạo Cảnh kết hợp Tán Đạo với Mộng Về Viễn Cổ để sáng chế Mộng Đạo thuật.","dacDiem":"Mở cánh cửa đạo thuật mới cho Vương Lâm","congNang":["Đạo thuật mang tính phá hủy đạo"],"tabs":{"tienTrinh":[{"chuong":"@c1333","loai":"nhac-toi","importance":"normal","giaiDoan":"Được nhắc là nguyên liệu Mộng Đạo","text":"Được nhắc lại: đạo thuật của lão giả Phong diệt tộc trong Phong giới năm xưa, mở ra hướng mới cho Vương Lâm sáng chế Mộng Đạo thuật.","anchor":"đối với Tán Đạo của lão già Phong diệt tộc trong Phong giới năm xưa lại có thể mở ra một cánh cửa đạo thuật mới"}]},"capNhatToi":"@c1333","nguon":["@c1333"]},{"id":"than-thong-bao-menh-chu-tuoc-toc","name":"Thần thông bảo mệnh Chu Tước tộc","cn":null,"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Một trong ba thuật mạnh nhất Chu Tước tộc","hePhai":"Chu Tước tộc","soHuu":["Lão Chu Tước","Vương Lâm"],"blurb":"Một trong ba thuật mạnh nhất của Chu Tước tộc, do Viễn Cổ tiên tôn truyền lại. Uy lực cực lớn nhưng thiêu đốt tuổi thọ, là thuật bảo mệnh không thể tùy tiện sử dụng.","detail":"Thần thông bảo mệnh được Viễn Cổ tiên tôn Chu Tước tộc truyền lại, xếp vào hàng ba thuật mạnh nhất của tộc. Lão Chu Tước hứa truyền cho Vương Lâm để đổi lại việc tuyển chọn Chu Tước đời thứ bảy. Thần thông Chu Tước tộc vốn cần người giữ nguyên thần chi dương hoàn hảo mới phát huy uy lực tối đa; Vương Lâm dù nguyên dương đã bị phá vẫn có thể tu luyện được một chút. Uy lực rất lớn nhưng cái giá là thiêu đốt tuổi thọ của người thi triển, nên chỉ dùng lúc nguy cấp bảo mệnh, không thể tùy tiện sử dụng.","nguon":["@c1335"]},{"id":"truyen-tong-tran-vuong-lam","name":"Truyền Tống trận (Vương Lâm tự tạo)","cn":null,"loai":"khac","loaiLabel":"Trận pháp","phamCap":null,"hePhai":null,"soHuu":["Vương Lâm"],"blurb":"Trận pháp truyền tống do Vương Lâm bấm quyết biến hóa cấm chế quanh thân thể hình thành, chuẩn bị xâm nhập thánh địa Hỏa Tước tộc.","detail":"Vương Lâm bấm quyết tạo cấm chế quanh thân thể, biến hóa hình thành một Truyền Tống trận. Khi mở ra, trận pháp cho phép Vương Lâm đi xuyên qua bằng phương thức đặc biệt. Mục đích là chờ khi Lưu Kim Bưu bị đưa vào thánh địa Hỏa Tước tộc, Vương Lâm sẽ dùng trận pháp này để xuyên qua xâm nhập vào bên trong.","nguon":["@c1335"]},{"id":"phan-gioi-co-tan","name":"Phần Giới Cổ Tán","cn":"","aliases":["Thần thông bảo mệnh Chu Tước tộc","Thuật mạnh nhất Chu Tước tộc","Thuật Ô lửa"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Thần thông cấp hủy diệt giới","hePhai":"Hỏa","soHuu":["Viễn Cổ Tiên Tôn","Điên Lạc đại đế","Lão Chu Tước","Vương Lâm"],"blurb":"Phần Giới Cổ Tán là thần thông mạnh nhất của Chu Tước tộc, do Viễn Cổ Tiên Hoàng học trộm từ nguồn không rõ rồi truyền lại dưới dạng không hoàn chỉnh. Thuật pháp ngưng gần hai trăm vạn ấn quyết thành hỏa cốt dạng cái ô, mỗi lần mở ô giải phóng sức mạnh hủy diệt cấp giới, song sai một ấn quyết cũng đủ gây phản phệ kinh khủng. (+) Đại thần thông đạo thuật cấp cao, bản gốc hoàn chỉnh nằm ở người điên. Chu Tước đời đầu tiên năm xưa chỉ học trộm, không nắm đầy đủ. [CAN-SOAT-GOP] (+) Thần thông hỏa tán của Vương Lâm được dùng để chống hình chiếu Lục Ma Châu. Trong lần này, nó tạo biển lửa nhưng không biến hóa bản chất như vài thần thông khác. [CAN-SOAT-GOP]","detail":"Phần Giới Cổ Tán bắt nguồn từ Viễn Cổ Tiên Hoàng — vị này học trộm thuật từ nguồn không rõ, chỉ truyền lại được bản không hoàn chỉnh cho lão tổ đời thứ nhất của Chu Tước tộc. Thuật pháp yêu cầu bốn lần ấn quyết lần lượt 999, 9.999, 99 vạn và 99 vạn ấn ký, tổng cộng gần hai trăm vạn ấn ký phải hoàn thành trong chín nhịp thở; mỗi ấn ký chứa toàn bộ sức mạnh nguyên thần cùng tu vi toàn thân kết hợp khẩu quyết đặc biệt. Ấn thứ nhất tạo hỏa cốt thẳng như cây gậy từ hư hỏa trên mi tâm, ấn thứ hai phóng sợi dây nối đỉnh hỏa cốt hướng ra ngoài thành hình cái ô chưa mở, ấn thứ ba và thứ tư cuốn thành cơn lốc với vô số hỏa long vờn quanh bên ngoài. Sức mạnh thật sự nằm ở hành động mở ô: Viễn Cổ Tiên Hoàng từng mở ô tám lần, hủy diệt vạn người một giới, nhưng lần thứ chín ngay Tiên Tôn cũng không dám","thuocTinh":"Hỏa","nguonGoc":"Viễn Cổ Tiên Hoàng học trộm từ nguồn không rõ, truyền qua lão tổ đời thứ nhất Chu Tước tộc","yeuCau":"Phải là hỏa tu, đánh gần hai trăm vạn ấn quyết trong chín nhịp thở, mỗi ấn ký chứa nguyên thần + tu vi toàn thân","uyLuc":"Viễn Cổ Tiên Hoàng mở ô tám lần, mỗi lần hủy diệt vạn người một giới; lần thứ chín ngay Tiên Tôn cũng không dám mở. Bản không hoàn chỉnh mà thuật đã đủ sức diệt thế.","dacDiem":"Thuật không hoàn chỉnh do Viễn Cổ Tiên Hoàng học trộm mà thành. Yêu cầu gần hai trăm vạn ấn ký hoàn thành trong chín nhịp thở, sai một ấn quyết gây phản phệ kinh khủng — tu vi Huyền Không trung kỳ cũng trọng thương, người không phải hỏa tu sẽ bị tiêu tan.","congNang":["Mỗi lần mở ô giải phóng sức mạnh hủy diệt cấp giới, Viễn Cổ Tiên Hoàng mở tám lần diệt vạn người một giới (@c1336)","Khi chưa mở ô, uy áp kinh thiên đã trùm phủ vùng rộng lớn (@c1336)","Bốn lần ấn quyết tạo hỏa cốt hình cái ô từ hư hỏa trên mi tâm, với vô số hỏa long vờn quanh bên ngoài (@c1336)"],"trangThai":"Vương Lâm đã nhận truyền thừa, khắc sâu ấn quyết","capNhatToi":"@c1336","nguoiTu":[{"ten":"Viễn Cổ Tiên Tôn","tuChuong":"@c1336","tangDatToi":"Mở ô tám lần","trangThai":"Truyền lại không hoàn chỉnh"},{"ten":"Điên Lạc đại đế","tuChuong":"@c1336","tangDatToi":"Mở ô năm lần","trangThai":"Không Kiếp sơ kỳ"},{"ten":"Lão Chu Tước","tuChuong":"@c1336","tangDatToi":"Mở ô hai lần","trangThai":"Huyền Không trung kỳ, nhờ nguyên dương"},{"ten":"Vương Lâm","tuChuong":"@c1336","tangDatToi":"Mới nhận truyền thừa","trangThai":"Đã khắc sâu ấn quyết"}],"tabs":{"tienTrinh":[{"chuong":"@c1336","loai":"he-lo-tang-chieu","importance":"major","giaiDoan":"Truyền thụ và biểu diễn lần đầu","text":"Lão Chu Tước biểu diễn Phần Giới Cổ Tán trước mặt Vương Lâm, đánh gần hai trăm vạn ấn quyết tạo hỏa cốt hình cái ô chưa mở, uy áp trùm Đại đế tinh và lan nửa vùng Điên Lạc. Tiết lộ nguồn gốc do Viễn Cổ Tiên Hoàng học trộm, không hoàn chỉnh. Trao ngọc giản cho Vương Lâm, Vương Lâm khắc sâu rồi hủy.","anchor":"thuật mạnh nhất của Chu Tước tộc ta, Phần Giới Cổ Tán"}]},"nguon":["@c1336","@c1449","@c1782"]},{"id":"mo-trang-day-gieng","name":"Mò Trăng Đáy Giếng","cn":"井底捞月","aliases":["Mò trăng đáy giếng"],"loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đại thần thông","hePhai":"Chưởng Tôn","soHuu":["Chưởng Tôn"],"blurb":"Đại thần thông của Chưởng Tôn, biến tinh không thành mặt nước hình giếng phản chiếu mọi thứ, rồi thò tay mò bóng phản chiếu lên để bắt hồn phách kẻ địch. Bá đạo cực kỳ, ngay cả đối thủ tu vi cao hơn cũng có thể bị tan hồn hoặc bị phát hiện, kẻ bị mò hồn bất động không thể nói hay phản kháng.","detail":"Mò Trăng Đáy Giếng là thuật của Chưởng Tôn. Khi thi triển, kẻ thí triển tung một trảo biến tinh không thành mặt nước hình giếng; tất cả thần thông, pháp bảo, thân thể đối phương đều bị phản chiếu trong nước và đứng yên bất động. Sau đó thò tay mò bóng phản chiếu lên, bắt được hồn phách đối phương. Thuật này cực kỳ bá đạo — bình thường kẻ bị mò hồn không thể nói hay phản kháng, ngay cả tu vi cao hơn cũng bị tan hồn hoặc bị phát hiện. Triết lý của thuật: trong giếng vốn không có trăng, dù xuất hiện cũng chỉ là ánh trăng phản chiếu trên trời. Vương Lâm từng dùng Cổ Ma Hồn thế chỗ hồn phách bản thân nên thoát được. Tại @c1338, Chưởng Tôn tung một trảo thi triển thuật này, biến tinh không thành mặt nước hình giếng, phản chiếu toàn bộ thần thông và thân thể đối phương.","thuocTinh":"Hồn phách","nguonGoc":"Thuật của Chưởng Tôn","uyLuc":"Bá đạo cực kỳ, ngay cả đối thủ tu vi cao hơn cũng có thể bị tan hồn hoặc bị phát hiện.","dacDiem":"Chỉ cần một thuật, biến tinh không thành giếng nước phản chiếu. Triết lý: trong giếng vốn không có trăng, dù xuất hiện cũng chỉ là ánh trăng phản chiếu trên trời.","congNang":["Biến tinh không thành mặt nước hình giếng, phản chiếu toàn bộ thần thông, pháp bảo và thân thể đối phương @c1338","Mò bóng phản chiếu lên bắt hồn phách kẻ địch","Kẻ bị mò hồn bất động, không thể nói hay phản kháng"],"nguoiTu":[{"ten":"Chưởng Tôn","tuChuong":"@c1338","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1338","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Chưởng Tôn tung một trảo biến tinh không thành mặt nước hình giếng, phản chiếu toàn bộ thần thông và thân thể Vương Lâm, mò bóng phản chiếu lên bắt hồn. Tuy nhiên thứ bị mò là Cổ Ma Hồn chứ không phải hồn thật Vương Lâm.","anchor":"Thức thần thông này của bổn tôn có tên là. Mò trăng đáy giếng. Trong giếng vốn không có trăng"}]},"nguon":["@c1338"]},{"id":"trach-luu-tuoc-vu","name":"Trạch Lưu Tước Vũ","cn":"","aliases":[],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Chu Tước tộc","soHuu":["Vương Lâm"],"blurb":"Trạch Lưu Tước Vũ là khẩu quyết do Chu Tước đời thứ nhất truyền cho Vương Lâm, dùng để triệu hoán nguyên linh của Chu Tước tộc từ Thái Cổ Giới giáng lâm. Khi thi triển, Vương Lâm tự xưng Chu Tước đời thứ sáu, rút lông Chu Tước hóa biển lửa bao trùm bầu trời rồi đọc khẩu quyết để kích hoạt thuật triệu hoán.","detail":"Trạch Lưu Tước Vũ là bí thuật triệu hoán được Chu Tước đời thứ nhất truyền lại cho Vương Lâm. Khi sử dụng, Vương Lâm rút lông Chu Tước hóa thành biển lửa bao trùm bầu trời, tự xưng thân phận Chu Tước đời thứ sáu rồi đọc khẩu quyết Trạch Lưu Tước Vũ. Thông qua nghi thức này, nguyên linh của Chu Tước tộc từ Thái Cổ Giới được triệu gọi giáng lâm. Khẩu quyết gắn liền với huyết mạch truyền thừa của Chu Tước tộc, lấy lông Chu Tước làm môi giới dẫn đường.","nguonGoc":"Chu Tước đời thứ nhất truyền cho Vương Lâm","congNang":["Triệu hoán nguyên linh Chu Tước tộc từ Thái Cổ Giới giáng lâm @c1338","Rút lông Chu Tước hóa biển lửa bao trùm bầu trời làm môi giới cho thuật triệu hoán @c1338"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1338","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1338","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Vương Lâm rút lông Chu Tước hóa biển lửa bao trùm bầu trời, tự xưng Chu Tước đời thứ sáu, đọc khẩu quyết Trạch Lưu Tước Vũ triệu nguyên linh Chu Tước tộc từ Thái Cổ Giới giáng lâm.","anchor":"Chu Tước đời thứ sáu ta, lấy Trạch Lưu Tước Vũ, gọi ra nguyên linh của Chu Tước tộc ta"}]},"nguon":["@c1338"]},{"id":"tu-dai-giai-khong-thuat","name":"Tứ Đại Giai Không Thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đại thần thông","hePhai":"Chưởng Tôn (Thiểm Lôi tộc)","soHuu":["Chưởng Tôn"],"blurb":"Tứ Đại Giai Không Thuật là thần thông do Chưởng Tôn thi triển, triệu xuất bốn tầng nguyên tố Địa, Thủy, Hỏa, Phong xếp chồng tấn công diện rộng, tu vi phát huy vượt xa Thủy Đạo Tử và Tư Mặc Tử. Thuật này được dùng để đối kháng nguyên linh Chu Tước chân chính, sức xung kích đủ phá nát thánh địa.","detail":"Tứ Đại Giai Không Thuật là thần thông cấp cao, khi thi triển người sử dụng quát lên Địa, Thủy, Hỏa, Phong rồi Tứ Đại Giai Không, lần lượt triệu xuất mặt đất vô biên, sóng biển cuồn cuộn, lửa bảy màu ngợp trời và cuồng phong — bốn tầng nguyên tố xếp chồng lao lên đối kháng mục tiêu. Tại chương 1339, Chưởng Tôn phải phun máu bấm quyết mới thi triển được thuật này nhằm đối kháng nguyên linh Chu Tước chân chính, cho thấy đây là chiêu thức tiêu hao cực lớn nhưng mang uy lực tương xứng. Lực xung kích nếu va chạm đủ phá nát thánh địa Hỏa Tước tộc, thể hiện sức hủy diệt cấp diệt thế.","thuocTinh":"Địa, Thủy, Hỏa, Phong","uyLuc":"Lực xung kích diệt thế, đủ phá nát thánh địa Hỏa Tước tộc.","dacDiem":"Bốn tầng nguyên tố xếp chồng, tu vi phát huy vượt xa Thủy Đạo Tử và Tư Mặc Tử; thi triển đòi hỏi phun máu bấm quyết, tiêu hao cực lớn.","congNang":["Triệu xuất bốn tầng nguyên tố Địa, Thủy, Hỏa, Phong xếp chồng, tạo thành tấn công diện rộng quy mô cực lớn @c1339","Đối kháng nguyên linh Chu Tước chân chính, phát huy tu vi vượt xa Thủy Đạo Tử và Tư Mặc Tử @c1339"],"nguoiTu":[{"ten":"Chưởng Tôn","tuChuong":"@c1339","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1339","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Chưởng Tôn phun máu bấm quyết thi triển Tứ Đại Giai Không Thuật đối kháng nguyên linh Chu Tước chân chính, bốn tầng nguyên tố lần lượt va chạm rồi tan vỡ sau bốn nhịp thở.","anchor":"Địa , thủy, hỏa, phong!"}]},"nguon":["@c1339"]},{"id":"thuat-bao-menh-bat-tinh-co-than","name":"Thuật bảo mệnh bát tinh Cổ Thần — Cổ chi tí hữu","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Thuật bảo mệnh bát tinh Cổ Thần là bí thuật phòng ngự tối thượng gắn liền với hộ tí Cổ chi tí hữu, triệu hoán hình ảnh Cổ Thần hư ảo khổng lồ bảo vệ chủ nhân và phản kích với uy lực áp đảo. Thuật này được Vương Lâm kích hoạt trong trận chiến sinh tử với Chưởng Tôn, thể hiện sức mạnh vượt trội cả về phòng thủ lẫn tấn công.","detail":"Khi thi triển, chủ nhân đặt tay trái lên hộ tí Cổ Thần trên tay phải, dồn toàn bộ sức mạnh Cổ Thần vào hộ tí. Một Cổ Thần hư ảo khổng lồ được triệu hoán, toàn thân đầy vết thương, ôm chủ nhân vào lòng như cha mẹ che chở con cái. Trong trận chiến với Chưởng Tôn, chưởng ấn của Chưởng Tôn đánh vào lưng Cổ Thần hư ảo lập tức tan vỡ, cho thấy phòng ngự cực kỳ kiên cố. Ngay sau đó, Cổ Thần xoay người tung một quyền với tám tinh điểm trên mi tâm xoay tròn, đánh trúng Chưởng Tôn khiến hắn hoàn toàn trọng thương. Sau khi hoàn thành sứ mệnh, Cổ Thần hư ảo tiêu tan, trở lại thành hộ tí dung nhập vào tay phải chủ nhân. Thuật này được Vương Lâm sử dụng tại mốc @c1340.","thuocTinh":"Cổ Thần","uyLuc":"Chưởng ấn của Chưởng Tôn đánh vào lưng Cổ Thần hư ảo liền tan vỡ; Cổ Thần tung một quyền với tám tinh điểm xoay tròn đánh trúng Chưởng Tôn khiến hắn hoàn toàn trọng thương.","congNang":["Triệu hoán Cổ Thần hư ảo khổng lồ ôm chủ nhân vào lòng, bảo vệ toàn diện trước công kích của đối phương @c1340","Hóa giải chưởng ấn cường địch — chưởng ấn Chưởng Tôn đánh vào lưng Cổ Thần lập tức tan vỡ @c1340","Phản kích bằng quyền lực của Cổ Thần với tám tinh điểm trên mi tâm xoay tròn, đủ sức đánh Chưởng Tôn hoàn toàn trọng thương @c1340"],"dacDiem":"Cổ Thần hư ảo được triệu hoán toàn thân đầy vết thương, ôm chủ nhân vào lòng như cha mẹ che chở con; mi tâm có tám tinh điểm xoay tròn khi phản kích. Sau khi thi triển xong, Cổ Thần tiêu tan trở lại thành hộ tí dung nhập tay phải.","nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1340","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1340","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu kích hoạt","text":"Vương Lâm kích hoạt trong trận chiến với Chưởng Tôn, triệu hoán Cổ Thần hư ảo khổng lồ ôm mình bảo vệ. Cổ Thần tung quyền đánh Chưởng Tôn hoàn toàn trọng thương, thương thế hàng vạn năm bùng phát.","anchor":"Thuật bảo mệnh bát tinh Cổ Thần, cổ chi tí hữu"}]},"nguon":["@c1340"]},{"id":"truong-sinh-an","name":"Trường sinh ấn","cn":"长生印","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Giới ngoại","soHuu":[],"blurb":"Trường sinh ấn là pháp thuật do sư tôn của Chưởng Tôn — nhân vật cùng tề danh Viễn Cổ Tiên Tôn thời Thái Cổ — nắm giữ, có khả năng hồi sinh người chết bằng cách thu thập hồn phách hàng vạn sinh linh hóa thành ấn. Pháp thuật này được Chưởng Tôn đề cập nhằm dụ dỗ Vương Lâm nhưng bị từ chối.","detail":"Trường sinh ấn được tiết lộ khi Chưởng Tôn dụ dỗ Vương Lâm bằng lời hứa sẽ cầu sư tôn của mình thi triển thuật này. Sư tôn của Chưởng Tôn là nhân vật cùng tề danh Viễn Cổ Tiên Tôn thời Thái Cổ, có khả năng thực hiện Trường sinh ấn. Điều kiện thi triển đòi hỏi phải tìm được một sinh linh giới, giết hàng vạn người để lấy hồn phách, dùng số hồn phách đó hóa thành Trường sinh ấn. Ấn này có thể hồi sinh người đã chết, cụ thể Chưởng Tôn đề cập có thể hồi sinh cả Lý Mộ Uyển và Vương Bình cho Vương Lâm. Tuy nhiên, Vương Lâm đã từ chối đề nghị này.","congNang":["Hồi sinh người chết bằng cách thu thập hồn phách hàng vạn sinh linh hóa thành ấn @c1341"],"nguonGoc":"Sư tôn Chưởng Tôn — nhân vật cùng tề danh Viễn Cổ Tiên Tôn thời Thái Cổ","dacDiem":"Đại giá cực lớn: cần tìm sinh linh giới, giết hàng vạn người lấy hồn phách để hóa thành ấn; chỉ có thể được thi triển bởi cường giả ngang hàng Viễn Cổ Tiên Tôn thời Thái Cổ.","tabs":{"tienTrinh":[{"chuong":"@c1341","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu được đề cập","text":"Chưởng Tôn dụ dỗ Vương Lâm bằng lời hứa cầu sư tôn tìm sinh linh giới, giết hàng vạn người lấy hồn phách hóa Trường sinh ấn hồi sinh Lý Mộ Uyển và Vương Bình. Vương Lâm từ chối.","anchor":"giết hàng vạn người, lấy hồn phách của họ hóa thành Trường sinh ấn"}]},"nguon":["@c1341"]},{"id":"lac-diep-quy-can","name":"Lạc diệp quy căn","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thuật triệu hồi cho phép Vương Lâm gọi lại Cổ Tức Diệp từ xa sau khi nó tiêu tan, chiếc lá biến thành tinh quang xuất hiện trước mặt.","detail":"Vương Lâm bấm quyết niệm chú triệu hồi Cổ Tức Diệp sau khi nó hóa tinh quang tiêu tan, chiếc lá tái hiện trước mặt dưới dạng tinh quang.","nguon":["@c1343"]},{"id":"phong-an-dai-than-thong-phong-diet-toc","name":"Phong ấn đại thần thông Phong Diệt tộc","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Phong Diệt tộc","soHuu":["Thiếu nữ Phong Diệt tộc"],"blurb":"Đại thần thông của Phong Diệt tộc, có khả năng phong ấn hết thảy thần thông và đường lui của đối thủ.","detail":"Thiếu nữ Phong Diệt tộc bắt đầu triệu hồi phong ấn của tộc để phong ấn đường lui Vương Lâm, nhưng bị huyết kiếm xuyên mi tâm gián đoạn trước khi hoàn thành. Phong Diệt tộc là chủng tộc thái cổ hiếm thấy, có khả năng phong ấn hết thảy thần thông.","congNang":["Phong ấn hết thảy thần thông và đường lui của đối phương"],"nguoiTu":[{"ten":"Thiếu nữ Phong Diệt tộc","tuChuong":"@c1344","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1344","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu hé lộ","text":"Thiếu nữ Phong Diệt tộc triệu hồi phong ấn đại thần thông để phong ấn đường lui Vương Lâm, nhưng bị huyết kiếm xuyên mi tâm gián đoạn trước khi hoàn thành.","anchor":"Hậu nhân Phong diệt tộc, gọi về đại thần thông phong ấn của tộc ta, phong ấn đường lui của người này"}]},"nguon":["@c1344"]},{"id":"menh-ba-hon-phong-diet-toc","name":"Mệnh ba hồn (Phong Diệt tộc)","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật / Đặc tính chủng tộc","phamCap":"Không rõ","hePhai":"Phong Diệt tộc","soHuu":["Thiếu nữ Phong Diệt tộc"],"blurb":"Mệnh ba hồn là đặc tính chủng tộc của Phong Diệt tộc, cho phép người sở hữu chết rồi hồi sinh, tổng cộng ba mạng. Vết thương sau khi hồi sinh sẽ khép lại nhưng để lại sẹo vĩnh viễn.","detail":"Phong Diệt tộc thiên phú sở hữu mệnh ba hồn — tức mỗi thành viên của tộc này có tổng cộng ba mạng, khi bị giết chết vẫn có thể hồi sinh. Tại @c1344, thiếu nữ Phong Diệt tộc bị Vương Lâm dùng huyết kiếm xuyên mi tâm, chết đi một lần, song nhờ mệnh ba hồn mà hồi sinh; vết thương khép lại nhưng để sẹo vĩnh viễn. Đây là lần đầu tiên trong đời nàng suýt chết thật sự, đồng thời cũng là lần đầu mệnh ba hồn phát huy tác dụng trên nàng.","congNang":["Chết rồi hồi sinh, tổng cộng ba mạng @c1344","Vết thương sau hồi sinh khép lại nhưng để sẹo vĩnh viễn @c1344"],"tabs":{"tienTrinh":[{"chuong":"@c1344","loai":"hé lộ tầng-chiêu","importance":"major","giaiDoan":"Lần đầu kích hoạt","text":"Thiếu nữ Phong Diệt tộc bị huyết kiếm xuyên mi tâm chết một lần, nhờ mệnh ba hồn mà hồi sinh, vết thương khép lại để sẹo vĩnh viễn.","anchor":"nếu không phải Phong diệt tộc ta có mệnh ba hồn thì vừa rồi. ta đã chết rồi"}]},"nguon":["@c1344"],"uyLuc":"Ngay cả khi bị huyết kiếm xuyên mi tâm — một đòn chí mạng — vẫn có thể hồi sinh nhờ mệnh ba hồn @c1344.","dacDiem":"Đặc tính chủng tộc bẩm sinh của Phong Diệt tộc, không phải công pháp tu luyện; mỗi lần hồi sinh đều lưu lại sẹo vĩnh viễn tại vị trí vết thương trí mạng."},{"id":"bat-phuong-cuc-lang-dao","name":"Bát phương cực lang đạo","cn":"八方极狼道","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Phụng Thiên Lang tộc","soHuu":["Đại hán Phụng Thiên lang tộc"],"blurb":"Thần thông của Phụng Thiên Lang tộc, hai tay bắt quyết triệu hoán tám hư ảnh sói khổng lồ mấy ngàn trượng từ tám hướng lao tới mục tiêu tấn công.","detail":"Đại hán Phụng Thiên Lang tộc thi triển, thân thể truyền ra tiếng sói tru, biến ảo tám hư ảnh sói lớn mấy ngàn trượng ở tám hướng lao tới Vương Lâm. Bị cơn lốc sương mù cổ mộ đánh tan tành.","congNang":["Triệu hoán 8 hư ảnh sói khổng lồ tấn công mục tiêu từ tám hướng"],"nguoiTu":[{"ten":"Đại hán Phụng Thiên lang tộc","tuChuong":"@c1345","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1345","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Đại hán Phụng Thiên Lang tộc thi triển nhắm vào Vương Lâm, triệu tám hư ảnh sói khổng lồ mấy ngàn trượng. Bị cơn lốc sương mù cổ mộ đánh tan.","anchor":"Bát phương cực lang đạo! Đại hán phụng Thiên Lang tộc quát khẽ"}]},"nguon":["@c1345"]},{"id":"tinh-trung-lao-nguyet","name":"Tĩnh Trung Lao Nguyệt","cn":"靜中撈月","aliases":["Tĩnh trung lao nguyệt","Mò trăng dưới giếng"],"loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Không rõ","soHuu":["Lão già hắc bào (trong đại điện)"],"blurb":"Tĩnh Trung Lao Nguyệt là một thuật thao túng tâm trí từ xa, sử dụng mặt nước tĩnh như gương kết hợp ba ngọn nến để phong ấn thân ảnh mục tiêu và can thiệp vào tư duy của đối phương. Thuật bị phá vỡ khi mục tiêu bước vào sương mù cổ mộ khiến mặt nước nổi sóng, thân ảnh tiêu tan. (+) Đạo thuật lấy mặt đất làm giếng, phản chiếu bầu trời, từ trong giếng mò ra ảo ảnh để giết hồn đối phương. [CAN-SOAT-GOP]","detail":"Kẻ hắc bào trong cung điện ẩn giấu giữa tinh không Thái Cổ Tinh Thần đã thi triển Tĩnh Trung Lao Nguyệt, dùng giếng nước tĩnh lặng làm môi giới phản chiếu ba ngọn nến cùng thân ảnh tóc bạc của Vương Lâm bị phong ấn bên trong. Thông qua phản ảnh này, hắn gieo những ý tưởng điên cuồng vào tâm trí mục tiêu, khiến mục tiêu tưởng rằng đó là suy nghĩ tự phát, đồng thời che giấu mọi mối nghi ngờ nảy sinh. Khi Vương Lâm bước vào vùng sương mù cổ mộ, mặt nước giếng lập tức nổi sóng, thân ảnh bị phong ấn vặn vẹo rồi tiêu tan, thuật pháp thất bại hoàn toàn.","thuocTinh":"Thao túng tâm trí","nguonGoc":"Không rõ","yeuCau":"Giếng nước tĩnh + ba ngọn nến","uyLuc":"Thao túng tư duy mục tiêu từ xa, gieo ý tưởng và che giấu nghi ngờ mà mục tiêu không hay biết","dacDiem":"Cần ba ngọn nến kết hợp mặt nước tĩnh như gương để phong ấn thân ảnh mục tiêu làm môi giới; bị ngăn trở khi mục tiêu vào vùng sương mù cổ mộ — mặt nước nổi sóng, thân ảnh tiêu tan, thuật pháp thất bại","congNang":["Thao túng tâm trí mục tiêu từ xa thông qua phản ảnh thân ảnh trong giếng nước tĩnh @c1346","Gieo ý tưởng vào đầu mục tiêu khiến mục tiêu tưởng là suy nghĩ tự phát @c1346","Che giấu nghi ngờ trong tâm trí mục tiêu, ngăn đối phương nhận ra mình bị thao túng @c1346"],"nguoiTu":[{"ten":"Lão già hắc bào (trong đại điện)","tuChuong":"@c1346","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1346","loai":"thi triển","importance":"major","giaiDoan":"Thao túng Vương Lâm thất bại","text":"Kẻ hắc bào dùng giếng nước + ba ngọn nến phong ấn thân ảnh Vương Lâm để thao túng tâm trí. Khi Vương Lâm vào sương mù cổ mộ, thân ảnh tiêu tan, thuật thất bại.","anchor":"Tĩnh trung lao nguyệt, chỉ thiếu có một chút"}]},"capNhatToi":"@c1346","nguon":["@c1346","@c1678"]},{"id":"dich-thien-an","name":"Dịch Thiên Ấn","loai":"than-thong","loaiLabel":"Thần thông","soHuu":["Vương Lâm"],"blurb":"Thần thông chưởng ấn hư ảo biến ảo vô biên, tốc độ cực nhanh, uy lực khủng khiếp.","detail":"Vương Lâm thi triển, chưởng ấn hư ảo biến ảo vô biên xuyên thấu sương mù ngàn trượng, một chiêu nghiền nát tu sĩ thiên nhân đệ tam suy.","congNang":["Chưởng ấn hư ảo xuyên thấu sương mù, nghiền nát đối thủ bằng một chiêu @c1348"],"tabs":{"tienTrinh":[{"chuong":"@c1348","loai":"thi triển","importance":"normal","giaiDoan":"Sử dụng trong cổ mộ","text":"Vương Lâm thi triển Dịch Thiên Ấn giết tu sĩ trung niên đánh lén, chưởng ấn xuyên thấu sương mù nghiền nát đối phương, lập uy trước mấy trăm tu sĩ.","anchor":"Dịch Thiên Ấn lập tức ầm ầm hiện ra, thu hút sự chú ý của tuyệt đại tu sĩ bốn phía"}]},"nguon":["@c1348"]},{"id":"cam-che-phong-an-vien-ngoai","name":"Cấm chế phong ấn (tu sĩ viên ngoại)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Tu sĩ béo mập viên ngoại (bàn tính)"],"blurb":"Nâng tay biến ảo ra vô số cấm chế khiến tu sĩ sững lại, bị phong ấn rơi xuống biển sương mù.","detail":"Thần thông phong ấn hàng loạt của tu sĩ mập mạp viên ngoại. Nâng tay biến ảo ra vô số cấm chế rơi vào đám tu sĩ, khiến họ bị phong ấn thân thể và rơi xuống biển sương mù.","congNang":["Phong ấn thân thể đối thủ hàng loạt"],"nguoiTu":[{"ten":"Tu sĩ béo mập viên ngoại (bàn tính)","tuChuong":"@c1350","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1350","loai":"thi triển","importance":"normal","giaiDoan":"Thi triển lần đầu","text":"Tu sĩ viên ngoại nâng tay biến ảo cấm chế phong ấn hàng loạt tu sĩ trên đài cao, khiến họ rơi xuống biển sương mù.","anchor":"nâng tay biến ảo ra vô số cấm chế, rơi vào đám tu sĩ điên cuồng xông tới"}]},"nguon":["@c1350"]},{"id":"than-thong-me-mang-lao-ba-ao-luc","name":"Thần thông mê mang (lão bà áo lục)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"","soHuu":["Lão bà áo lục"],"blurb":"Thần thông khiến tất cả tu sĩ xung quanh mê mang không tỉnh táo, tự nguyện rời khỏi đài cao mà không cần chiến đấu.","detail":"Khi lão bà áo lục tới gần, toàn bộ tu sĩ đều lộ vẻ không tỉnh táo, hơn mười người tự lùi đi. Bà chiếm đài cao mà không cần đánh.","congNang":["Khiến đối phương mê mang, mất tỉnh táo, tự nguyện rời đi"],"nguoiTu":[{"ten":"Lão bà áo lục","tuChuong":"@c1350","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1350","loai":"thi triển","importance":"normal","giaiDoan":"Thi triển lần đầu","text":"Khiến toàn bộ mười tu sĩ xung quanh mê mang không tỉnh táo, chiếm đài cao mà không cần chiến đấu.","anchor":"khi bà ta tới gần thì toàn bộ mười người đều lộ vẻ không tỉnh táo"}]},"nguon":["@c1350"]},{"id":"phong-huyen-thuat","name":"Phong Huyễn Thuật","cn":"风幻术","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Phong Huyễn Tộc","soHuu":["Lão bà áo lục"],"blurb":"Bí thuật của Phong Huyễn Tộc (tam đại kỳ tộc). Phun sương mù đỏ nhạt từ miệng, tạo ảo giác khiến người nhìn thấy người chí thân thay vì thí thuật giả, kích động cảm xúc bảo vệ.","detail":"Bà lão áo lục bị Vương Lâm ép phải sử dụng Phong Huyễn Thuật trong vùng đất cổ mộ. Phun sương mù đỏ nhạt, tạo ảo giác khiến tất cả người xung quanh nhìn thấy người chí thân quen thuộc thay vì bà ta, kích động phẫn nộ bảo vệ. Bị Tuế Nguyệt nhất chỉ của Vương Lâm phá tan hoàn toàn.","thuocTinh":"Ảo giác / mê hoặc","nguonGoc":"Phong Huyễn Tộc, một trong tam đại kỳ tộc","congNang":["Tạo ảo giác người chí thân, mê hoặc địch thủ và người ngoài"],"tabs":{"tienTrinh":[{"chuong":"@c1353","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu lộ diện","text":"Bà lão áo lục bị ép sử dụng, phun sương mù đỏ nhạt tạo ảo giác người chí thân. Bị Tuế Nguyệt nhất chỉ phá tan.","anchor":"Đám hư ảnh này đều là những người Vương Lâm quen thuộc"}]},"nguon":["@c1353"]},{"id":"van-cam-pha-quyet","name":"Vạn cấm phá quyết","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Lão già thanh bào"],"blurb":"Thuật cấm chế do lão già thanh bào tự nghiên cứu gần ngàn năm sáng tạo ra, dùng để phá các cấm chế. Thất bại trước sương mù đỏ chứa Cổ Hồn cấm trên lưng Cổ Thần.","detail":"Thi triển bằng cách phóng ký hiệu cấm chế khổng lồ, ban đầu có khả năng áp chế cuồng phong nhưng không đủ sức phá Cổ Hồn cấm ít nhất lục phẩm, cả ký hiệu lẫn người thi triển đều bị sương mù nuốt chửng.","nguon":["@c1354"]},{"id":"thuat-gia-chet-tieu-tinh","name":"Thuật giả chết của Tiêu Tĩnh","cn":null,"loai":"than-thong","loaiLabel":"Thần thông","phamCap":null,"hePhai":null,"soHuu":["Tiêu Tĩnh"],"blurb":"Thần thông giả chết toàn diện, khiến bản thân giống thật sự đã chết, ngay cả nguyên thần cũng giả tan vỡ, người khác không thể phân biệt thật giả.","detail":"Tiêu Tĩnh thi triển thuật giả chết khiến toàn bộ khí tức sinh mệnh biến mất, nguyên thần cũng tan vỡ giả, thậm chí còn cố ý tạo bộ dạng thối rữa để tăng độ thuyết phục. Người thường hoàn toàn không thể phát hiện thật giả. Tuy nhiên đối với Vương Lâm — người thông hiểu ba trong tứ đại cấm chế và có kinh nghiệm phong phú — thì thuật này không có hiệu quả.","nguon":["@c1356"]},{"id":"loi-hoa-giao-hoa","name":"Lôi hỏa giao hòa","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông dung hợp lôi đình bổn nguyên và hỏa diễm bổn nguyên tại mi tâm, hóa thành thiểm điện bốc cháy lao như lưu tinh. Lần đầu được Vương Lâm thi triển tại chương @c1357, phá nát ngọn núi triệu từ Sơn Hải Đồ của tu sĩ bước thứ ba.","detail":"Vương Lâm dung hợp lôi đình bổn nguyên từ mắt phải và hỏa diễm bổn nguyên từ mắt trái, hội tụ hai luồng bổn nguyên tại mi tâm rồi phóng ra đòn tấn công tổng hợp dưới dạng thiểm điện bốc cháy lao như lưu tinh. Khi thi triển, Vương Lâm hô khẩu quyết \"Lôi hỏa giao hòa vạn pháp đại phá\" (@c1357). Đòn đánh đủ sức phá vỡ ngọn núi được triệu hoán từ Sơn Hải Đồ — một pháp bảo của tu sĩ bước thứ ba — cản bước đối phương.","thuocTinh":"Lôi + Hỏa","nguonGoc":"","yeuCau":"Sở hữu đồng thời lôi đình bổn nguyên và hỏa diễm bổn nguyên","uyLuc":"Phá vỡ ngọn núi được triệu hoán từ Sơn Hải Đồ, cản bước tu sĩ bước thứ ba.","dacDiem":"Dung hợp hai loại bổn nguyên — lôi đình và hỏa diễm — tại mi tâm thành một đòn tổng hợp, kèm khẩu quyết \"Lôi hỏa giao hòa vạn pháp đại phá\".","congNang":["Dung hợp lôi đình bổn nguyên và hỏa diễm bổn nguyên tại mi tâm, phóng ra đòn tấn công tổng hợp dạng thiểm điện bốc cháy lao như lưu tinh @c1357","Phá nát ngọn núi triệu từ Sơn Hải Đồ của tu sĩ bước thứ ba, cản bước đối phương @c1357"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1357","tangDatToi":"","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1357","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Vương Lâm lần đầu dung hợp lôi đình và hỏa diễm tại mi tâm, hô Lôi hỏa giao hòa vạn pháp đại phá, phóng thiểm điện bốc cháy phá nát ngọn núi từ Sơn Hải Đồ của Linh Động Thượng Nhân.","anchor":"Lôi hỏa giao hòa, vạn pháp đại phá!"}]},"capNhatToi":"@c1357","dinhDanh":"goc","nguon":["@c1357"]},{"id":"son-hai-do","name":"Sơn Hải Đồ","cn":"山海图","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Linh Động Thượng Nhân"],"blurb":"Thần thông của Linh Động Thượng Nhân, phun nguyên thần khí hóa bức tranh có biển rộng và ngọn núi để tấn công-phòng thủ.","detail":"Linh Động Thượng Nhân phun nguyên thần khí hóa bức tranh sơn hải. Chiêu Hải Khiếu triệu sóng biển cao trăm trượng đối kháng hư hỏa chín màu. Chiêu Sơn Lâm triệu ngọn núi lao vào đối phương. Biển bị hư hỏa bốc hơi hết, núi bị lôi hỏa giao hòa phá nát.","congNang":["Chiêu Hải Khiếu triệu sóng biển cao trăm trượng tấn công-phòng thủ","Chiêu Sơn Lâm triệu ngọn núi lao vào đối phương"],"nguoiTu":[{"ten":"Linh Động Thượng Nhân","tuChuong":"@c1357","tangDatToi":"","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1357","loai":"thi triển","importance":"normal","giaiDoan":"Đối kháng Vương Lâm trong thông đạo","text":"Linh Động Thượng Nhân phun nguyên thần khí hóa Sơn Hải Đồ, dùng chiêu Hải Khiếu triệu sóng biển đối kháng hư hỏa chín màu và chiêu Sơn Lâm triệu ngọn núi, nhưng đều bị Vương Lâm phá hủy.","anchor":"biển rộng bên trong bức sơn hải đồ của hắn lập tức điên cuồng trào ra"}]},"capNhatToi":"@c1357","dinhDanh":"goc","nguon":["@c1357"]},{"id":"linh-dong-dai-ma-gioi-thuy-dong-ma-than","name":"Linh Động Đại Ma Giới — Thủy Động Ma Thần","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật triệu hồi","phamCap":"","hePhai":"Ma đạo","soHuu":["Linh Động Thượng Nhân"],"blurb":"Bí thuật triệu hồi của Linh Động Tộc, mở Linh Động Đại Ma Giới bằng hương hỏa để gọi Thủy Động Ma Thần — pho tượng đen khổng lồ có sức mạnh hủy diệt.","detail":"Linh Động Thượng Nhân mở khe nứt Linh Động Đại Ma Giới, lấy hương hỏa triệu hồi Thủy Động Ma Thần — một pho tượng đen khổng lồ buông hai tay phóng lực hủy diệt. Sức mạnh khiến xương thịt người chịu như muốn rời ra. Bị Cổ Thần hư ảnh một quyền đánh nát.","congNang":["Triệu hồi Thủy Động Ma Thần từ ma giới Linh Động Tộc bằng hương hỏa"],"nguoiTu":[{"ten":"Linh Động Thượng Nhân","tuChuong":"@c1357","tangDatToi":"","trangThai":"đang tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1357","loai":"thi triển","importance":"normal","giaiDoan":"Triệu hồi trong tuyệt vọng","text":"Linh Động Thượng Nhân trong tuyệt vọng mở Linh Động Đại Ma Giới dùng hương hỏa gọi ra Thủy Động Ma Thần, nhưng pho tượng bị Cổ Thần hư ảnh một quyền phá nát.","anchor":"Mở ra Linh Động Đại Ma Giới, lấy hương hỏa của lão phu, gọi ra Thủy Động Ma Thần của Linh Động Tộc ta!"}]},"capNhatToi":"@c1357","dinhDanh":"goc","nguon":["@c1357"]},{"id":"thien-hoang-vuong-lo-thap-phu-luyen-no","name":"Thiên Hoàng Vương Lộ, Thập Phủ Luyện Nô","cn":"天皇王路，十斧炼奴","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Thiên Hoàng Vương Lộ, Thập Phủ Luyện Nô là pháp quyết sử dụng ngôn ngữ Cổ Thần để kích hoạt Thiên Hoàng Lô theo phương thức luyện nô, triệu hồi tám Cổ Thần toàn thân đỏ sẫm cầm búa lớn chém liên hoàn vào đối phương bên trong lò. Khác với luyện hóa thông thường, phương thức này nhằm biến đối phương thành nô bộc, uy lực đủ phá vỡ phòng ngự của cao thủ bước thứ ba tu đạo.","detail":"Pháp quyết bắt nguồn từ ngôn ngữ Cổ Thần, do Vương Lâm niệm chú kích hoạt Thiên Hoàng Lô chuyển sang chế độ luyện nô. Khi thi triển, sức mạnh Cổ Thần dung nhập vào lò, hồn phách của đối phương bị giam bên trong ngưng tụ thành hư ảnh Cổ Thần toàn thân đỏ sẫm, mỗi vị cầm một búa lớn. Tối đa tám Cổ Thần được triệu hồi liên tiếp, tám búa liên hoàn giáng xuống tấn công đối phương bên trong lò. Phương thức này không nhằm luyện hóa tiêu diệt mà là luyện nô — khuất phục đối phương, biến thành nô bộc. Vương Lâm thi triển pháp quyết này lần đầu được ghi nhận tại chương 1360.","thuocTinh":"Cổ Thần","nguonGoc":"Ngôn ngữ Cổ Thần","yeuCau":"Sức mạnh Cổ Thần, Thiên Hoàng Lô","uyLuc":"Tám Cổ Thần tám búa liên hoàn có uy lực phá vỡ phòng ngự của cao thủ bước thứ ba tu đạo.","dacDiem":"Cần niệm ngôn ngữ Cổ Thần để kích hoạt; hồn phách bên trong lò ngưng tụ thành hư ảnh Cổ Thần toàn thân đỏ sẫm cầm búa; bản chất là luyện nô chứ không phải luyện hóa tiêu diệt.","congNang":["Biến Thiên Hoàng Lô thành phương tiện luyện nô, chuyển từ luyện hóa thông thường sang khuất phục đối phương thành nô bộc @c1360","Triệu hồi tối đa tám Cổ Thần hồn phách toàn thân đỏ sẫm cầm búa lớn, tấn công liên hoàn đối phương bên trong lò @c1360"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1360","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1360","loai":"thi triển","importance":"major","giaiDoan":"Lần đầu sử dụng","text":"Vương Lâm niệm ngôn ngữ Cổ Thần kích hoạt Thiên Hoàng Lô theo phương thức luyện nô, triệu hồn liên tiếp tám Cổ Thần búa chém phá vỡ Ma Thần pho tượng của Linh Động Thượng Nhân.","anchor":"Thiên Hoàng Vương Lộ, thập phủ luyện nô!"}]},"capNhatToi":"@c1360","nguon":["@c1360"]},{"id":"ma-than-pho-tuong-linh-dong","name":"Ma Thần pho tượng (Linh Động)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Ma đạo","soHuu":["Linh Động Thượng Nhân"],"blurb":"Thần thông của Linh Động Thượng Nhân, triệu hồi pho tượng Ma Thần phòng ngự, có thể tái sinh từ máu tươi.","detail":"Linh Động bấm quyết triệu hồi pho tượng Ma Thần chống lại Cổ Thần búa bên trong Thiên Hoàng Lô. Pho tượng chịu được nhát búa đầu tiên rồi cùng tiêu tan, nhưng khi Linh Động phun máu, máu tươi lập tức hóa thành pho tượng đứng dậy lại. Tuy nhiên trước tám búa liên hoàn, pho tượng vỡ vụn không phục hồi được.","congNang":["Triệu hồi pho tượng Ma Thần phòng ngự","Pho tượng có thể tái sinh từ máu tươi người sử dụng"],"nguoiTu":[{"ten":"Linh Động Thượng Nhân","tuChuong":"@c1360","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1360","loai":"thi triển","importance":"normal","giaiDoan":"Dùng trong Thiên Hoàng Lô kháng cự","text":"Linh Động triệu hồi pho tượng Ma Thần đỡ búa Cổ Thần, pho tượng bị phá rồi tái sinh từ máu tươi, nhưng cuối cùng bị tám búa liên hoàn phá vỡ hoàn toàn.","anchor":"Linh Động Thượng Nhân phun ra máu tươi, nhưng máu tươi vừa xuất hiện lại lập tức hóa thành pho tượng kia"}]},"capNhatToi":"@c1360","nguon":["@c1360"]},{"id":"am-lang-diet-dao","name":"Âm lãng diệt đạo","cn":"阴浪灭道","loai":"than-thong","loaiLabel":"Thần thông","phamCap":null,"hePhai":"Diệu Âm Đạo Tôn","soHuu":["Diệu Âm Đạo Tôn"],"blurb":"Thần thông phản kích của Diệu Âm Đạo Tôn, kết hợp âm bổn nguyên và thủy bổn nguyên phát động khi trọng thương.","detail":"Khi Diệu Âm Đạo Tôn bị hợp kích trọng thương nặng (huyết kiếm Vương Lâm xuyên ngực phía sau, năm móng tay Đại Hoang đâm vỡ thuẫn trúng trước ngực), hắn phun máu rồi kích hoạt phản đòn: kết hợp âm bổn nguyên và thủy bổn nguyên thi triển Âm lãng diệt đạo. Đây là chiêu phản kích tuyệt vọng trong tình thế lưỡng diện thọ địch.","nguon":["@c1364"]},{"id":"am-thuy-dung-hop","name":"Âm Thủy Dung Hợp","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Âm đạo + Thủy đạo","soHuu":["Diệu Âm Đạo Tôn"],"blurb":"Âm Thủy Dung Hợp là pháp thuật cốt lõi của Diệu Âm Đạo Tôn — một trong Thái Cổ Ngũ Tôn — dung hợp âm đạo và thủy đạo thành tiếng biển gào thét mang uy lực hủy thiên diệt địa. Khi thi triển, chiêu thức này đã hủy diệt gần trăm tu sĩ và phá hủy hoàn toàn vùng đất phong ấn trong cổ mộ.","detail":"Âm Thủy Dung Hợp là sức mạnh cốt lõi của Diệu Âm Đạo Tôn, vị tôn giả nắm giữ âm bổn nguyên đại thành và thủy bổn nguyên thành chính quả. Bằng cách dung hợp hai đạo — âm đạo và thủy đạo — Diệu Âm tạo ra thanh âm biển gào thét có uy lực hủy thiên diệt địa. Trong trận chiến tại cổ mộ, chiêu thức này đã giết gần trăm tu sĩ trên mặt đất và phá hủy hoàn toàn vùng đất phong ấn.","congNang":["Dung hợp âm đạo và thủy đạo thành tiếng biển gào thét mang sức hủy diệt trên diện rộng @c1365","Sát thương hàng loạt, hủy diệt gần trăm tu sĩ cùng lúc @c1365","Phá hủy hoàn toàn vùng đất phong ấn trong cổ mộ @c1365"],"nguoiTu":[{"ten":"Diệu Âm Đạo Tôn","tuChuong":"@c1365","tangDatToi":"đại thành","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1365","loai":"thi triển","importance":"major","giaiDoan":"Thi triển trong đại chiến với Đại Hoang","text":"Diệu Âm dung hợp âm đạo và thủy đạo, tiếng biển gào thét hủy diệt gần trăm tu sĩ trên mặt đất, phá hủy vùng đất phong ấn, uy lực long trời lở đất.","anchor":"âm đ*o, thủy đạo kết hợp, nếu hình thành biển lớn thì âm thanh chính là thanh âm của biển"}]},"nguon":["@c1365"],"uyLuc":"Tiếng biển gào thét hủy thiên diệt địa, giết gần trăm tu sĩ trên mặt đất và phá hủy hoàn toàn vùng đất phong ấn trong cổ mộ.","dacDiem":"Kết hợp hai bổn nguyên đạo — âm đạo và thủy đạo — thành một chiêu thức dung hợp, biểu hiện dưới dạng thanh âm biển gào thét."},{"id":"dai-hoang-tam-tien","name":"Đại Hoang Tam Tiên","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Độc đạo","soHuu":["Đại Hoang Thượng Nhân"],"blurb":"Đại Hoang Tam Tiên là ba cây châm được Đại Hoang Thượng Nhân phong ấn trên môi suốt bốn vạn năm. Khi giải ấn, ba châm hóa ba đạo hắc quang cắm vào mi tâm đối phương, phối hợp ngũ độc gây trúng độc trầm trọng, khiến đối phương trọng thương gần chết.","detail":"Đại Hoang Tam Tiên là ba cây châm do Đại Hoang Thượng Nhân luyện hóa từ bốn vạn năm trước, xuyên qua môi tự phong ấn bản thân trong thời gian cực dài. Tại thời điểm khai phong (@c1365), Đại Hoang giải ấn ba châm, chúng lập tức hóa thành ba đạo hắc quang lao thẳng vào mi tâm Diệu Âm Đạo Tôn. Ba châm phối hợp với ngũ độc khiến Diệu Âm Đạo Tôn trọng thương gần chết. Sau đó, Linh Động còn đẩy ba châm sâu thêm một tấc vào mi tâm Diệu Âm, gia tăng sát thương.","congNang":["Phong ấn bản thân: ba châm xuyên qua môi Đại Hoang Thượng Nhân, duy trì tự phong ấn suốt bốn vạn năm","Giải ấn hóa hắc quang: khi khai phong, ba châm hóa ba đạo hắc quang cắm vào mi tâm đối phương, gây trúng độc trầm trọng (@c1365)","Phối hợp ngũ độc: kết hợp cùng ngũ độc khiến đối phương trọng thương gần chết"],"nguoiTu":[{"ten":"Đại Hoang Thượng Nhân","tuChuong":"@c1365","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1365","loai":"khai phong","importance":"major","giaiDoan":"Giải ấn bốn vạn năm trong đại chiến","text":"Đại Hoang giải ấn ba cây châm phong ấn bốn vạn năm trên môi, ba châm hóa hắc quang cắm vào mi tâm Diệu Âm Đạo Tôn, phối hợp ngũ độc khiến đối phương trọng thương gần chết.","anchor":"Lão phu bốn vạn năm trước đã luyện hóa Đại Hoang Tam Tiên thành những cây châm phong ấn ở trên miệng"}]},"nguon":["@c1365"],"uyLuc":"Ba châm hóa hắc quang cắm vào mi tâm Diệu Âm Đạo Tôn, phối hợp ngũ độc khiến đối phương trọng thương gần chết; sau đó bị Linh Động đẩy sâu thêm một tấc, gia tăng sát thương.","dacDiem":"Ba cây châm phong ấn trên môi chủ nhân suốt bốn vạn năm, khi giải ấn hóa hắc quang nhắm thẳng mi tâm đối phương, mang tính chất kịch độc."},{"id":"ngu-doc-thuat","name":"Ngũ Độc thuật","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Độc đạo","soHuu":["Đại Hoang Thượng Nhân"],"blurb":"Đại Hoang Thượng Nhân biến năm ngón tay bàn tay khổng lồ thành ngũ độc — rết, hắc xà một sừng, nhện đen, bọ cạp, cóc — tấn công rồi hóa hắc khí xâm nhập cơ thể đối phương.","detail":"Ngũ độc gồm rết trăm trượng, hắc xà một sừng trăm trượng, nhện đen, bọ cạp có đuôi phá vỡ hư vô, cóc u lưng chứa độc lực kinh khiếp. Sau khi bị biển tím Diệu Âm tấn công, ngũ độc hóa năm đạo hắc khí chui vào cơ thể Diệu Âm Đạo Tôn, phối hợp với ba châm Tam Tiên gây trúng độc toàn diện.","congNang":["Biến năm ngón tay thành ngũ độc tấn công diện rộng","Hóa hắc khí xâm nhập cơ thể đối phương gây trúng độc"],"nguoiTu":[{"ten":"Đại Hoang Thượng Nhân","tuChuong":"@c1365","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1365","loai":"thi triển","importance":"normal","giaiDoan":"Tung ngũ độc trong đại chiến với Diệu Âm","text":"Đại Hoang biến năm ngón bàn tay khổng lồ thành ngũ độc tấn công Diệu Âm, sau bị biển tím đánh tan nhưng ngũ độc hóa hắc khí chui vào cơ thể đối phương.","anchor":"Ngũ độc hiện ra, mang theo tinh phong sắc bén gào thét, lao thẳng tới Diệu âm đ*o Tôn"}]},"nguon":["@c1365"]},{"id":"hai-dan-gioi-than-thong","name":"Hải Dân Giới","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"Âm đạo + Thủy đạo","soHuu":["Diệu Âm Đạo Tôn"],"blurb":"Hải Dân Giới là hương hỏa giới riêng của Diệu Âm Đạo Tôn, chứa một vùng biển tím với hàng triệu sinh linh hương hỏa. Khi thi triển, khe không gian khổng lồ mấy vạn trượng bị xé mở, triệu hồi toàn bộ biển tím ào ra như đại hồng thủy tấn công diện rộng.","detail":"Hải Dân Giới là một vùng tinh không riêng biệt thuộc về Diệu Âm Đạo Tôn, bên trong chứa biển tím mênh mông cùng vô số sinh linh hương hỏa sinh sống. Khi Diệu Âm thi triển, bà xé mở khe không gian khổng lồ rộng mấy vạn trượng thông tới giới này, khe bị bức rộng gấp mười lần so với ban đầu, nước biển tím cùng hàng triệu sinh linh hương hỏa ào ạt tràn ra như đại hồng thủy, tạo thành đòn tấn công diện rộng cực kỳ khủng khiếp. Tuy nhiên, trong trận chiến, biển hương hỏa này đã bị cái lưỡi tím đen của Đại Hoang chạm vào và biến toàn bộ thành biển độc màu đen hôi thối, khiến chiêu thức bị vô hiệu hóa.","congNang":["Triệu hồi biển tím cùng hàng triệu sinh linh hương hỏa từ hương hỏa giới riêng, ào ra như đại hồng thủy tấn công diện rộng @c1365"],"nguoiTu":[{"ten":"Diệu Âm Đạo Tôn","tuChuong":"@c1365","tangDatToi":"đại thành","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1365","loai":"thi triển","importance":"major","giaiDoan":"Mở Hải Dân Giới tấn công Đại Hoang","text":"Diệu Âm mở khe mấy vạn trượng triệu biển tím hàng triệu sinh linh hương hỏa, ào ra như đại hồng thủy đánh tan thân thể phân hồn Đại Hoang, nhưng bị cái lưỡi Đại Hoang biến thành biển độc.","anchor":"Hải dân giới! Mở!"}]},"nguon":["@c1365"],"uyLuc":"Xé khe không gian mấy vạn trượng, triệu hồi cả một vùng biển hương hỏa với hàng triệu sinh linh tràn ra như đại hồng thủy, đánh tan mục tiêu trên phạm vi cực rộng.","dacDiem":"Là một vùng tinh không riêng biệt chứa biển tím với hàng triệu sinh linh hương hỏa; khi thi triển cần xé mở khe không gian khổng lồ mấy vạn trượng để dẫn biển ra ngoài."},{"id":"cai-luoi-tim-den","name":"Cái lưỡi tím đen","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"","hePhai":"Độc đạo","soHuu":["Đại Hoang Thượng Nhân"],"blurb":"Cái lưỡi quỷ dị màu tím đen phóng từ đôi môi Đại Hoang sau khi giải ấn Tam Tiên, chạm biển hương hỏa lập tức biến nó thành biển độc màu đen hôi thối.","detail":"Ẩn sau ba cây châm phong ấn trên môi Đại Hoang Thượng Nhân. Khi giải ấn, cái lưỡi không giống của con người phóng ra, chạm biển tím hương hỏa của Diệu Âm lập tức biến toàn bộ thành biển độc, vô hiệu hóa hoàn toàn Hải Dân Giới.","congNang":["Biến hương hỏa đối phương thành biển độc","Vô hiệu hóa Hải Dân Giới của Diệu Âm"],"nguoiTu":[{"ten":"Đại Hoang Thượng Nhân","tuChuong":"@c1365","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1365","loai":"thi triển","importance":"normal","giaiDoan":"Phóng lưỡi biến biển hương hỏa thành biển độc","text":"Cái lưỡi tím đen quỷ dị phóng ra từ đôi môi vừa giải ấn, chạm biển tím hương hỏa Diệu Âm biến toàn bộ thành biển độc màu đen hôi thối.","anchor":"Đó là một cái lưỡi! Một cái lưỡi dường như không thể nào là của một con người"}]},"nguon":["@c1365"]},{"id":"lay-luc-chung-dao-huyen-vu","name":"Phương pháp lấy lực chứng đạo của bộ tộc Huyền Vũ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Bộ tộc Huyền Vũ","soHuu":["Vương Lâm"],"blurb":"Phương pháp mượn lực phản chấn từ ngoại lực cực lớn để gia tăng tốc độ bản thân, xuất phát từ bộ tộc Huyền Vũ.","detail":"Vương Lâm thi triển khi bị bàn tay khổng lồ ném đi: dậm mạnh vào bàn tay tạo phản lực, dung nhập hai luồng lực (lực ném và phản lực) để tốc độ vượt hẳn Đại Hoang Thượng Nhân mà thoát ly.","thuocTinh":"Lực","nguonGoc":"Bộ tộc Huyền Vũ","uyLuc":"Mượn phản chấn từ ngoại lực cực lớn, dung nhập hai luồng lực để bứt tốc vượt tu sĩ cùng cấp","congNang":["Mượn lực phản chấn từ ngoại lực cực lớn để gia tăng tốc độ bản thân"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1367","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1367","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu thi triển","text":"Vương Lâm dậm mạnh vào bàn tay khổng lồ khi bị ném, mượn phản lực dung nhập hai luồng lực vượt qua Đại Hoang Thượng Nhân thoát ly.","anchor":"thi triển phương pháp lấy lực chứng đạo của bộ tộc Huyền Vũ"}]},"nguon":["@c1367"]},{"id":"tran-phap-dau-lau","name":"Trận pháp đầu lâu","cn":"","loai":"khac","loaiLabel":"Trận pháp","phamCap":"Không rõ","hePhai":"Ma đạo","soHuu":["Cửu Thiên ma tôn"],"blurb":"Trận pháp được hình thành từ đám đầu lâu chất đống trên đài mộ sáu ngàn trượng của Cửu Thiên ma tôn, mùi máu tanh tràn ngập.","detail":"Đám đầu lâu nhìn như hỗn loạn nhưng thực tế tạo thành trận pháp trên đài mộ sáu ngàn trượng.","tabs":{"tienTrinh":[{"chuong":"@c1368","loai":"xuất hiện","importance":"normal","giaiDoan":"Lộ diện trên đài mộ Cửu Thiên ma tôn","text":"Đám đầu lâu chất đống trên đài mộ sáu ngàn trượng của Cửu Thiên ma tôn trong mảnh bản đồ thứ sáu, nhìn hỗn loạn nhưng thực tế tạo thành trận pháp.","anchor":"Đám đầu lâu này nhìn thì như hỗn loạn nhưng trên thực tế lại trở thành một trận pháp"}]},"nguon":["@c1368"]},{"id":"chuong-an-khong-lo","name":"Chưởng ấn khổng lồ","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"","hePhai":"","soHuu":["Vương Lâm"],"blurb":"Thần thông bắt quyết vung chưởng ấn hấp thụ nguyên lực vô tận, đánh xuống tạo lực phản chấn cực mạnh làm sụp đất.","detail":"Vương Lâm bắt quyết vung ra một chưởng ấn khổng lồ hấp thụ nguyên lực, đánh xuống nứt mặt đất lộ ra đầu lâu Cổ Thần cửu tinh bên dưới.","congNang":["Hấp thụ nguyên lực, tạo chưởng ấn khổng lồ đánh sụp mặt đất @c1369"],"nguon":["@c1369"],"tabs":{"tienTrinh":[{"chuong":"@c1369","loai":"thi triển","importance":"normal","giaiDoan":"Dùng tại rừng trên đầu lâu Cổ Thần","text":"Vương Lâm bắt quyết vung chưởng ấn hấp thụ nguyên lực đánh xuống mặt đất, làm sụp lộ đầu lâu Cổ Thần cửu tinh.","anchor":"Một chưởng ấn khổng lồ ầm ầm hiện ra"}]}},{"id":"dao-thuat-dung","name":"Đạo thuật Dung","cn":"","loai":"bi-thuat","loaiLabel":"Đạo thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Vương Lâm","Linh Động Thượng Nhân"],"blurb":"Đạo thuật Dung là đạo thuật do Vương Lâm truyền cho Linh Động thông qua lạc ấn phóng vào mi tâm, có tác dụng tăng tốc hấp thụ hồn phách hương hỏa nhằm hỗ trợ tiến vào bước thứ ba.","detail":"Tại chương 1370, Vương Lâm truyền đạo thuật Dung cho Linh Động bằng cách phóng một lạc ấn chứa đạo thuật vào mi tâm hắn. Đạo thuật này chuyên dùng để tăng tốc quá trình hấp thụ hồn phách hương hỏa, từ đó hỗ trợ người tu luyện chính thức tiến vào bước thứ ba. Linh Động sau khi tiếp nhận đã bắt đầu cảm ngộ ngay lập tức.","congNang":["Tăng tốc hấp thụ hồn phách hương hỏa, hỗ trợ tiến vào bước thứ ba @c1370"],"nguoiTu":[{"ten":"Linh Động Thượng Nhân","tuChuong":"@c1370","tangDatToi":"","trangThai":"dang-cam-ngo"}],"tabs":{"tienTrinh":[{"chuong":"@c1370","loai":"xuất hiện","importance":"major","giaiDoan":"Truyền thụ lần đầu","text":"Vương Lâm truyền đạo thuật Dung cho Linh Động qua lạc ấn vào mi tâm, giúp hắn nhanh chóng hấp thụ hồn phách hương hỏa để tiến bước thứ ba.","anchor":"Đạo thuật, Dung! Ngươi hãy nhanh chóng cảm ngộ thuật này!"}]},"nguon":["@c1370"]},{"id":"than-thong-phung-thien-lang-toc","name":"Thần thông Phụng Thiên Lang Tộc","cn":"","loai":"than-thong","loaiLabel":"Thần thông bản tộc","phamCap":"Không rõ","hePhai":"Phụng Thiên Lang tộc","soHuu":["Đại hán Phụng Thiên Lang tộc"],"blurb":"Thần thông bản tộc của Phụng Thiên Lang tộc, phối hợp với chín chiếc lá có thể khóa Phụng Thiên Lang Đạo vĩnh viễn bên người.","detail":"Đại hán Phụng Thiên Lang tộc cho biết nếu lấy được chín chiếc lá và phối hợp thần thông bản tộc, có thể làm cho Phụng Thiên Lang Đạo vĩnh viễn ở lại bên người, trở thành kẻ Không Niết Sơ Kỳ mạnh nhất.","congNang":["Phối hợp chín chiếc lá khóa Phụng Thiên Lang Đạo vĩnh viễn bên người"],"nguoiTu":[{"ten":"Đại hán Phụng Thiên Lang tộc","tuChuong":"@c1370","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1370","loai":"hé lộ tầng-chiêu","importance":"normal","giaiDoan":"Hé lộ công năng","text":"Đại hán Phụng Thiên Lang tộc tiết lộ thần thông bản tộc có thể phối hợp chín chiếc lá để khóa Phụng Thiên Lang Đạo vĩnh viễn bên người.","anchor":"phối hợp với thần thông của tộc ta, có thể làm cho Phụng Thiên Lang Đạo vĩnh viễn ở lại bên người"}]},"nguon":["@c1370"]},{"id":"tam-menh-thuat","name":"Tam mệnh thuật","cn":"三命术","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Phong Diệt tộc","soHuu":["Phong Diệt tộc"],"blurb":"Tam mệnh thuật là bí thuật truyền thừa của Phong Diệt tộc, gắn liền với tộc ấn và nghi thức tế tổ. Tộc nhân sống sót qua tế tổ sẽ được tộc ấn ban cho ba mạng sống; thuật này có thể bị người ngoài cướp dùng thông qua tế đàn nhưng tỉ lệ thất bại cao và thất bại sẽ bị phản phệ. (+) Thần thông cảm ngộ trên tế đàn Phong Diệt Tộc, thành công sẽ sở hữu ba tính mạng. [CAN-SOAT-GOP] (+) Bí thuật của Phong Diệt Tộc trong Thái Cổ Tinh Thần, cần gom đủ ba phần tế đàn mới tu luyện được. Gồm ba bước: trảm tam hồn, trảm tam thân, trảm thần — luyện thành thì thực lực tăng rất nhiều nhưng có nguy hiểm. [CAN-SOAT-GOP] (+) Thần thông phản kích mạnh mẽ, Vương Lâm quyết định dùng để cho kẻ truy kích bài học khó quên, mỗi lần sử dụng tiêu hao một lần cơ hội. [CAN-SOAT-GOP] (+) Thuật pháp bảo mệnh được Vương Lâm xem là hậu thủ để đánh cược cơ duyên Thiên Ngưu Hồn Khải. [CAN-SOAT-GOP] (+) Tam Mệnh Thuật là thần thông bảo mệnh giúp Vương Lâm hồi sinh sau khi tự hủy thân thể và Nguyên Thần trước hoàng cung. [CAN-SOAT-GOP]","detail":"Tam mệnh thuật là bí thuật cốt lõi của Phong Diệt tộc, nguồn gốc từ tế đàn và tộc ấn của tộc. Tộc nhân Phong Diệt tộc sau khi trải qua nghi thức tế tổ và sống sót sẽ được tộc ấn khắc vào thân, từ đó sở hữu ba mạng sống. Thuật này không hoàn toàn độc quyền cho tộc nhân: người ngoài có thể cướp đoạt và sử dụng trên chính bản thân mình, nhưng điều kiện tiên quyết là phải có tế đàn — vật đã mất tích từ lâu — và khả năng thành công không lớn; nếu thất bại sẽ bị phản phệ. Bí mật về Tam mệnh thuật được Phong Chỉ Mạn khai ra (@c1371). Diệu Âm đạo tôn nhận Phong Chỉ Mạn làm thị nữ chính vì mục đích đoạt lấy Tam mệnh thuật, song chưa thực hiện được.","thuocTinh":"Sinh mệnh","nguonGoc":"Tế đàn Phong Diệt tộc, tộc ấn","yeuCau":"Phải có tộc ấn Phong Diệt tộc, cần tế đàn (đã mất tích) để cướp dùng","uyLuc":"Ban ba mạng sống cho người sở hữu, cho phép chết đi sống lại.","dacDiem":"Gắn liền với tộc ấn Phong Diệt tộc và nghi thức tế tổ; người ngoài muốn cướp dùng cần tế đàn đã thất lạc, tỉ lệ thất bại cao và thất bại sẽ bị phản phệ.","congNang":["Ban cho tộc nhân Phong Diệt tộc ba mạng sống sau khi tế tổ sống sót và được tộc ấn (@c1371)","Có thể bị người ngoài cướp dùng trên bản thân họ, nhưng cần có tế đàn và tỉ lệ thành công thấp (@c1371)"],"trangThai":"hoat-dong","capNhatToi":"@c1371","tabs":{"tienTrinh":[{"chuong":"@c1371","loai":"he-lo-tang-chieu","importance":"major","giaiDoan":"Lộ toàn bộ cơ chế","text":"Phong Chỉ Mạn khai ra bí mật: tộc nhân sau tế tổ được tộc ấn có ba mạng. Có thể bị cướp dùng nhưng cần tế đàn đã mất tích, tỉ lệ thành công thấp, thất bại bị phản phệ. Diệu Âm đạo tôn tìm Phong Chỉ Mạn chính vì mục đích này.","anchor":"Thuật này có thể bị người khác cướp đi dùng trên chính thân thể mình"}]},"nguon":["@c1371","@c1413","@c1617","@c1665","@c1702","@c1779","@c1919"]},{"id":"thuat-phong-an-phong-diet-toc","name":"Thuật phong ấn Phong Diệt tộc","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Phong Diệt tộc","soHuu":["Phong Diệt tộc"],"blurb":"Thần thông phong ấn của Phong Diệt tộc, hiến tế tính mạng mở tộc ấn để tràn ra sức mạnh tổ tiên tiến hành phong ấn.","detail":"Tộc nhân Phong Diệt tộc hiến tế tính mạng, mở ra tộc ấn, từ bên trong tộc ấn tràn ra sức mạnh của tổ tiên để thực hiện phong ấn. Đại giá là phải mất đi tính mạng.","congNang":["Phong ấn dựa vào sức mạnh tổ tiên","Đại giá: hiến tế tính mạng"],"trangThai":"hoat-dong","capNhatToi":"@c1371","tabs":{"tienTrinh":[{"chuong":"@c1371","loai":"he-lo-tang-chieu","importance":"normal","giaiDoan":"Lộ cơ chế phong ấn","text":"Phong Chỉ Mạn khai ra: sức mạnh phong ấn đến từ hiến tế tính mạng mở tộc ấn, tràn ra sức mạnh tổ tiên.","anchor":"Hiến tế tính mạng, mở ra tộc ấn, từ bên trong tộc ấn sẽ tràn ra sức mạnh của tổ tiên"}]},"nguon":["@c1371"]},{"id":"quan-lang-bai-nguyet","name":"Quần Lang Bái Nguyệt","cn":"群狼拜月","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Phụng Thiên Lang tộc","soHuu":["Chu Cẩn"],"blurb":"Thần thông của Phụng Thiên Lang tộc, từ hai tay mọc vô số gai nhọn giống nanh sói hóa thành hơn mười vạn con sói triệu hoán mặt trăng đỏ như máu, tản uy áp bước thứ ba. (+) Thần thông của Chu Cẩn, triệu hồi huyết lang vạn trượng cùng hồng nguyệt đỏ máu xé bầu trời tấn công diện rộng. [CAN-SOAT-GOP]","detail":"Chu Cẩn thi triển khi bị dồn vào đường cùng: từ hai tay mọc vô số gai nhọn giống nanh sói, hóa thành hơn mười vạn con sói hung dữ ngẩng đầu triệu hoán mặt trăng đỏ như máu, tản uy áp bước thứ ba. Tuy nhiên chưa hoàn thành đã bị Vương Lâm dùng Thiên Hoàng Lô phóng to bao phủ thiên địa che khuất mặt trăng, bao vây mấy vạn con sói.","nguoiTu":[{"ten":"Chu Cẩn","tuChuong":"@c1372","tangDatToi":"Chưa hoàn thành","trangThai":"bị chặn"}],"congNang":["Triệu hoán hơn mười vạn con sói + mặt trăng đỏ như máu, tản uy áp bước thứ ba"],"tabs":{"tienTrinh":[{"chuong":"@c1372","loai":"thi triển","importance":"normal","giaiDoan":"Lần đầu xuất hiện","text":"Chu Cẩn thi triển khi bị dồn vào đường cùng, từ hai tay mọc vô số gai nhọn giống nanh sói hóa thành hơn mười vạn sói triệu hoán mặt trăng đỏ. Chưa hoàn thành đã bị Thiên Hoàng Lô che khuất mặt trăng và bao vây sói.","anchor":"những gai nhọn này thoạt nhìn như là nanh sói"}]},"nguon":["@c1372","@c1417"]},{"id":"tam-toc-luc-dung-hop","name":"Tam tộc lực dung hợp","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Cổ Thần + Cổ Ma + Cổ Yêu","soHuu":["Vương Lâm"],"blurb":"Tam tộc lực dung hợp là sức mạnh đặc biệt sinh ra từ việc dung hợp ba loại khí tức cổ đại — Cổ Thần lực, Cổ Ma lực và Cổ Yêu lực — vượt xa uy lực của bất kỳ loại nào đơn lẻ. Vương Lâm lần đầu thi triển tại cổ mộ, dùng để xóa thành công dấu ấn con số trên mi tâm thiếu nữ Phong Diệt tộc.","detail":"Trong cổ mộ, Vương Lâm ban đầu thử dùng riêng Cổ Thần lực để xóa dấu ấn con số trên mi tâm thiếu nữ Phong Diệt tộc nhưng thất bại. Sau đó hắn rút Cổ Ma lực từ Cổ Hồn Bình, Cổ Yêu lực từ hồ lô, rồi dung hợp cả ba loại khí tức cổ đại lại với nhau. Sức mạnh sinh ra từ sự dung hợp này vượt xa bất kỳ loại đơn lẻ nào, mang lại cảm giác có thể nắm giữ thiên địa. Vương Lâm dùng sức mạnh ấy vuốt lên mi tâm thiếu nữ, xóa thành công dấu ấn con số.","congNang":["Dung hợp Cổ Thần lực, Cổ Ma lực và Cổ Yêu lực thành một thể sức mạnh thống nhất vượt xa từng loại đơn lẻ @c1373","Xóa được dấu ấn con số trong cổ mộ — thứ mà Cổ Thần lực đơn độc không thể xóa @c1373"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1373","tangDatToi":"Lần đầu thành công","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1373","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu dung hợp thành công","text":"Vương Lâm dung hợp Cổ Thần lực, Cổ Ma lực, Cổ Yêu lực thành sức mạnh đặc biệt vượt xa cả ba, dùng xóa thành công dấu ấn con số trên mi tâm thiếu nữ Phong Diệt tộc.","anchor":"ba khí tức trong phút chốc ngưng tụ, lập tức ở trên tay phải Vương Lâm hoàn toàn dung hợp lại với nhau, hình thành một sức mạnh đặc biệt"}]},"nguon":["@c1373"],"uyLuc":"Sức mạnh sau dung hợp vượt xa bất kỳ loại khí tức cổ đại nào khi dùng riêng lẻ, mang lại cảm giác có thể nắm giữ thiên địa.","dacDiem":"Yêu cầu đồng thời ba nguồn khí tức cổ đại từ ba bộ tộc — Cổ Thần lực, Cổ Ma lực (từ Cổ Hồn Bình) và Cổ Yêu lực (từ hồ lô) — hợp nhất thành một thể duy nhất mới phát huy được uy lực."},{"id":"phuong-phap-tu-tao-an-ky-tam-toc-co","name":"Phương pháp tự tạo ấn ký tam tộc cổ","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"Tam tộc cổ (Cổ Thần + Cổ Ma + Cổ Yêu)","soHuu":["Vương Lâm"],"blurb":"Phương pháp do Vương Lâm tự khám phá, dung hợp Cổ Thần lực, Cổ Ma lực và Cổ Yêu khí trên mi tâm để tự ngưng tụ ấn ký, rồi lôi xuống dung nhập đài mộ thăng cấp mà không cần giết người đoạt phù. Đây là phương pháp phá vỡ quy tắc vùng đất cổ mộ, chỉ khả thi với thân phận Cổ Thần của Vương Lâm.","detail":"Tại vùng đất cổ mộ, tu sĩ thông thường phải giết người đoạt phù để thu ấn ký thăng cấp đài mộ. Vương Lâm phát hiện rằng khi dung hợp ba nguồn khí tức của tam tộc cổ — Cổ Thần lực (bản thân sở hữu, có thể tái sinh), Cổ Ma lực (thu được từ bóp nát Cổ Ma hồn) và Cổ Yêu khí (nguồn hiếm nhất, lấy từ hồ lô, muốn bổ sung phải phá hủy bảo vật Cổ Yêu) — đánh vào mi tâm, sẽ khiến ấn ký dạng con số tự sinh ra. Nhờ bản thân là Cổ Thần, mi tâm hắn vốn không cần ấn ký để tồn tại trong cổ mộ, nên hắn có thể lôi ấn ký từ mi tâm xuống mà không bị sương mù xóa sổ. Ấn ký sau đó được dung nhập đài mộ để thăng cấp. Phương pháp này tiêu hao cả ba nguồn khí tức, trong đó Cổ Yêu khí là nguồn khan hiếm nhất. Chỉ Vương Lâm mới thực hiện được do điều kiện tiên quyết là thân Cổ Thần. @c1374","congNang":["Tự ngưng tụ ấn ký trên mi tâm bằng cách dung hợp khí tức tam tộc cổ, không giới hạn số lượng, không cần giết người đoạt phù @c1374","Lôi ấn ký từ mi tâm xuống dung nhập đài mộ để thăng cấp đài mộ @c1374"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1374","tangDatToi":"Thuần thục","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1374","loai":"xuất hiện","importance":"major","giaiDoan":"Phát hiện và ứng dụng","text":"Vương Lâm thí nghiệm dung hợp khí tức tam tộc cổ trên mi tâm, phát hiện ấn ký tự sinh rồi lôi xuống dung nhập đài mộ. Lặp lại hàng trăm lần trong mấy canh giờ, thăng đài mộ từ hơn cấp sáu lên cấp bảy rồi cấp tám.","anchor":"Ba thứ này nhanh chóng dung hợp viên mãn trong nháy mắt"}]},"nguon":["@c1374"],"dacDiem":"Yêu cầu dung hợp đồng thời ba nguồn khí tức tam tộc cổ (Cổ Thần lực, Cổ Ma lực, Cổ Yêu khí); chỉ thân Cổ Thần mới thực hiện được vì mi tâm không cần ấn ký để tồn tại trong cổ mộ; tiêu hao Cổ Ma hồn và Cổ Yêu khí mỗi lần sử dụng, trong đó Cổ Yêu khí là nguồn hiếm nhất."},{"id":"bi-thuat-hap-thu-ky-hieu-nu-tu-ao-trang","name":"Bí thuật hấp thu ký hiệu rải rác (nữ tử áo trắng)","cn":"","loai":"bi-thuat","loaiLabel":"Bí thuật","phamCap":"Không rõ","hePhai":"","soHuu":["Nữ tử áo trắng"],"blurb":"Bí thuật riêng của nữ tử áo trắng, có thể hấp thu ký hiệu rải rác trong vùng đất cổ mộ để thăng cấp đài mộ mà không cần giết người.","detail":"Nữ tử bạch y ở bản đồ thứ tám sở hữu bí thuật đặc biệt thu hút những ký hiệu phân tán trong vùng đất cổ mộ, khác với cách giết người đoạt phù thông thường. Nhờ bí thuật này nàng thăng đài mộ lên cấp bảy.","nguoiTu":[{"ten":"Nữ tử áo trắng","tuChuong":"@c1374","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1374","loai":"xuất hiện","importance":"normal","giaiDoan":"Sử dụng thăng cấp đài mộ cấp bảy","text":"Nữ tử áo trắng dùng bí thuật hấp thu ký hiệu rải rác, đài mộ bành trướng thành cấp bảy.","anchor":"ta bởi vì có bí thuật nên mới có thể hấp thu những ký hiệu rải rác trong vùng đất cổ mộ này"}]},"nguon":["@c1374"]},{"id":"cach-son-chi-tien","name":"Cách Sơn Chi Tiên","cn":"隔山之仙","loai":"than-thong","loaiLabel":"Đạo thuật","phamCap":"Chỉ dưới Tinh Trung Lao Nguyệt","hePhai":"","soHuu":["Cửu Thiên Ma Tôn"],"blurb":"Cách Sơn Chi Tiên là đại đạo thuật nổi tiếng của Cửu Thiên Ma Tôn, được xếp hạng chỉ dưới Tinh Trung Lao Nguyệt trong các đạo thuật của vị này. Khi thi triển, người dùng điểm vào mi tâm, chỉ cần đã từng nhìn thấy thân ảnh đối phương một lần thì bổn tôn có thể vượt qua khoảng cách không gian mà tới giết mục tiêu.","detail":"Cách Sơn Chi Tiên là một trong những đại đạo thuật đứng đầu của Cửu Thiên Ma Tôn, uy thế chỉ xếp sau Tinh Trung Lao Nguyệt. Khi thi triển, người dùng điểm vào mi tâm, thân ảnh mục tiêu xuất hiện trong đồng tử rồi bị vặn vẹo, sau đó bổn tôn có thể vượt không gian tìm tới giết đối phương — điều kiện duy nhất là đã từng nhìn thấy thân ảnh mục tiêu ít nhất một lần. Tại bản đồ thứ tám trong cổ mộ, Cửu Thiên Ma Tôn thi triển đạo thuật này định giết Vương Lâm, nhưng bị bạch y nữ tử (Tiên phi) dùng Tinh môn chặn phá; cả hai bên đều chịu chấn thương sau đòn đối kháng đó (@c1376).","congNang":["Vượt qua khoảng cách không gian tới giết mục tiêu đã từng nhìn thấy thân ảnh ít nhất một lần (@c1376)"],"nguoiTu":[{"ten":"Cửu Thiên Ma Tôn","tuChuong":"@c1376","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1376","loai":"thi triển","importance":"major","giaiDoan":"Thi triển lần đầu trong cổ mộ","text":"Cửu Thiên Ma Tôn điểm vào mi tâm thi triển Cách Sơn Chi Tiên định giết Vương Lâm xuyên không gian, nhưng bị bạch y nữ tử mở Tinh môn chặn phá. Hai đạo thuật va chạm, cánh cửa tan biến, Cửu Thiên Ma Tôn phun máu lùi mấy trăm trượng.","anchor":"đại đạo thuật nổi tiếng chỉ dưới Tinh Trung Lao Nguyệt"}]},"nguon":["@c1376"],"uyLuc":"Đại đạo thuật đứng thứ hai của Cửu Thiên Ma Tôn, chỉ dưới Tinh Trung Lao Nguyệt; khi bị Tiên phi dùng Tinh môn chặn phá, cả hai bên đều chịu chấn thương, cho thấy sức mạnh ngang ngửa cấp tuyệt đỉnh (@c1376).","dacDiem":"Khi thi triển, người dùng điểm vào mi tâm, thân ảnh mục tiêu hiện trong đồng tử rồi bị vặn vẹo; điều kiện kích hoạt là đã từng nhìn thấy thân ảnh đối phương một lần, bổn tôn liền có thể xuyên không gian tới sát."},{"id":"thien-mon-tam-dao-tinh-mon","name":"Thiên môn tam đạo Nhật Nguyệt Tinh — Tinh môn","cn":"","loai":"than-thong","loaiLabel":"Đạo thuật","phamCap":"","hePhai":"","soHuu":["Nữ tử áo trắng"],"blurb":"Đạo thuật của bạch y nữ tử (Tiên phi), thuộc hệ Thiên môn tam đạo Nhật Nguyệt Tinh. Mở Tinh môn tạo cánh cửa khổng lồ có sức phòng ngự và phản kích mạnh.","detail":"Bạch y nữ tử bắt quyết mở Tinh môn, tạo ra cánh cửa khổng lồ trông giống cửa bước vào bước thứ ba nhưng thực chất khác. Cánh cửa này đủ sức chặn đạo thuật Cách Sơn Chi Tiên của Cửu Thiên Ma Tôn, nhưng sau va chạm thì tan biến, cả hai bên đều bị chấn thương.","congNang":["Tạo cánh cửa khổng lồ phòng ngự và phản kích"],"nguoiTu":[{"ten":"Nữ tử áo trắng","tuChuong":"@c1376","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1376","loai":"thi triển","importance":"normal","giaiDoan":"Chặn Cách Sơn Chi Tiên cứu Vương Lâm","text":"Bạch y nữ tử bắt quyết mở Tinh môn tạo cánh cửa khổng lồ chặn đạo thuật Cách Sơn Chi Tiên. Hai đạo thuật va chạm, cánh cửa tan biến, bạch y nữ tử sắc mặt tái nhợt bị chấn lùi trăm trượng.","anchor":"Thiên môn tam đạo Nhật Nguyệt Tinh. Tinh môn mở ra"}]},"nguon":["@c1376"]},{"id":"ky-hieu-dung-hop-ba-bo-toc","name":"Ký hiệu dung hợp ba bộ tộc","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Cổ Yêu + Cổ Ma + Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Ký hiệu dung hợp ba bộ tộc là ký hiệu kỳ dị do Vương Lâm tự chế tạo bằng cách dung hợp khí tức Cổ Yêu, Cổ Ma hồn và Cổ Thần lực, dùng để nạp vào đài mộ nâng cấp. Cửu Thiên Ma Tôn kinh ngạc nhận xét ngoài Thác Sâm thì không ai tự chế tạo được ký hiệu.","detail":"Vương Lâm tự chế tạo ký hiệu bằng cách dung hợp ba nguồn sức mạnh bộ tộc cổ: khí tức Cổ Yêu (từ vòng xoáy), Cổ Ma hồn (tuôn ra từ Ma Hồn Bình) và Cổ Thần lực (kích phát tinh điểm trên mi tâm). Ba sức mạnh hòa quyện thành một sức mạnh kỳ dị, hóa thành ký hiệu bao phủ toàn thân, sau đó được nạp vào đài mộ khiến đài mộ tăng trưởng đạt cấp chín. Cửu Thiên Ma Tôn kinh ngạc nhận xét rằng ngoài Thác Sâm ra thì không ai có thể tự chế tạo được ký hiệu, cho thấy đây là thành tựu cực kỳ hiếm có (@c1377).","congNang":["Dung hợp ba nguồn sức mạnh Cổ tộc (khí tức Cổ Yêu, Cổ Ma hồn, Cổ Thần lực) tạo thành ký hiệu kỳ dị bao phủ toàn thân @c1377","Nạp vào đài mộ để nâng cấp đài mộ, khiến đài mộ tăng trưởng đạt cấp chín @c1377"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1377","tangDatToi":"","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1377","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu thi triển","text":"Vương Lâm dung hợp khí tức Cổ Yêu, Cổ Ma hồn và Cổ Thần lực tự chế tạo ký hiệu kỳ dị, nạp vào đài mộ tám ngàn trượng khiến tăng lên chín ngàn trượng đạt cấp chín. Cửu Thiên Ma Tôn kinh ngạc nhận xét ngoài Thác Sâm không ai làm được.","anchor":"sức mạnh của ba bộ tộc hóa thành một sức mạnh kỳ dị có thể biến thành ký hiệu"}]},"nguon":["@c1377"],"uyLuc":"Nạp ký hiệu vào đài mộ khiến đài mộ tăng trưởng đạt cấp chín; Cửu Thiên Ma Tôn kinh ngạc nhận xét ngoài Thác Sâm không ai tự chế tạo được ký hiệu (@c1377).","dacDiem":"Ký hiệu được tự chế tạo từ sự dung hợp ba nguồn sức mạnh bộ tộc cổ đại riêng biệt — khí tức Cổ Yêu từ vòng xoáy, Cổ Ma hồn từ Ma Hồn Bình, Cổ Thần lực kích phát từ tinh điểm trên mi tâm — hòa thành một thể thống nhất kỳ dị bao phủ toàn thân trước khi nạp vào đài mộ."},{"id":"mo-dai-thang-cap","name":"Mộ đài thăng cấp (lực dẫn dắt)","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Cổ Thần","soHuu":["Vương Lâm"],"blurb":"Lực dẫn dắt xuất hiện trong tâm thần Vương Lâm mỗi khi mộ đài thăng cấp, hướng dẫn hắn thực hiện hành động then chốt. Lần thứ năm, lực này khiến hắn ngồi lên chiếc ghế khổng lồ trên đài trong đại điện cổ mộ, kích hoạt thân Cổ Thần và uy áp mười tám tinh điểm.","detail":"Thanh âm từ mộ đài thăng cấp đã năm lần xuất hiện trong tâm thần Vương Lâm, mỗi lần dẫn dắt hắn đến một bước ngoặt quan trọng. Lần thứ năm, lực dẫn dắt thúc đẩy hắn bước lên đài và ngồi lên chiếc ghế khổng lồ bên trong đại điện cổ mộ, từ đó kích hoạt biến hóa thân Cổ Thần cùng mười tám tinh điểm quỹ đạo đồng nhất.","tabs":{"tienTrinh":[{"chuong":"@c1379","loai":"thi triển","importance":"major","giaiDoan":"Lần thứ năm xuất hiện","text":"Lần thứ năm lực dẫn dắt từ mộ đài thăng cấp xuất hiện trong tâm thần Vương Lâm, khiến hắn ngồi lên ghế trên đài, kích hoạt thân Cổ Thần mấy trăm trượng và mười tám tinh điểm quỹ đạo đồng nhất.","anchor":"từ trong thanh âm lúc trước hiện lên trong những lần mộ đài thăng cấp, lần thứ năm xuất hiện trong tâm thần Vương Lâm"}]},"nguon":["@c1379"],"congNang":["Xuất hiện trong tâm thần Vương Lâm khi mộ đài thăng cấp, dẫn dắt hắn thực hiện hành động then chốt @c1379","Lần thứ năm khiến Vương Lâm ngồi lên ghế trên đài trong đại điện cổ mộ, kích hoạt thân Cổ Thần và uy áp mười tám tinh điểm @c1379"]},{"id":"than-chan-binh-tu-liet-vi","name":"Thần chấn — Binh Tu Liệt Vị","cn":"神震·兵屠列位","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Đạo cổ thuật","hePhai":"Thần (Cổ Thần tộc)","soHuu":["Đạo cổ Diệp Mịch","Vương Lâm"],"blurb":"Bước đầu tiên của Đạo Cổ Vô Tiên, dùng Cổ Thần cửu tinh xoay tròn dung nhập vào quyền, khiến thiên địa xoay quanh vị trí quyền. (+) Một quyền đánh ra khiến mấy ngàn tu sĩ bị xếp thành hàng chinh tề, nội tạng nguyên thần bị đánh nát, toàn bộ tử vong. [CAN-SOAT-GOP] (+) Câu quyết thần thông đầu trong chuỗi sát chiêu cuối chương của Vương Lâm. [CAN-SOAT-GOP] (+) Chuỗi thần thông Đạo Cổ được Vương Lâm dùng để chấn động tâm thần và cưỡng ép đội hình tu sĩ địch xếp thành hàng. [CAN-SOAT-GOP] (+) Một câu quyết trong chuỗi thi triển Cổ đạo vô tiên của Vương Lâm. [CAN-SOAT-GOP]","detail":"Thuật thuộc hệ Thần trong bốn hệ thần-yêu-ma-cổ của Đạo cổ Diệp Mịch. Khi thi triển, một quyền mang sức chấn động thiên địa đánh ra, ép mấy ngàn tu sĩ xếp thành hàng chinh tề rồi giết sạch trong nháy mắt, nội tạng nguyên thần đều bị đánh nát. Vương Lâm mượn khí thế truyền thừa trên đài cao cổ mộ, hóa thân thành Diệp Mịch mà thi triển thuật này.","nguon":["@c1380","@c1384","@c1683","@c1763","@c1794","@c1836"],"tabs":{}},{"id":"yeu-thuat-phong-hoa-thanh-son","name":"Yêu thuật — Phong Hỏa Thành Sơn","cn":"妖术·烽火成山","loai":"bi-thuat","loaiLabel":"Yêu thuật","phamCap":"Đạo cổ thuật","hePhai":"Yêu (Cổ Yêu tộc)","soHuu":["Đạo cổ Diệp Mịch","Vương Lâm"],"blurb":"Bước thứ hai của Đạo Cổ Vô Tiên, dùng Cổ Yêu bát tinh dung nhập chưởng tạo tám cột khói phong hỏa có hư ảnh cổ Yêu gào thét, nối thành cơn lốc. (+) Vung tay tạo ngọn yêu hỏa xanh biếc, khói hiệu bốc lên hóa thành tám ngọn yên sơn phát ra lực hút nuốt sạch hơn mười vạn tu sĩ. [CAN-SOAT-GOP] (+) Yêu thuật được Vương Lâm thi triển ngay sau Thần Chấn trong trận lập uy tại Đại Hồn Môn. Chương dừng ở khoảnh khắc hắn biến quyền thành chưởng vung ra nên uy lực đầy đủ chưa lộ. [CAN-SOAT-GOP] (+) Thần thông Đạo Cổ gom lang yên trên thiên linh của nhiều tu sĩ thành núi khổng lồ để trấn áp. [CAN-SOAT-GOP] (+) Một câu quyết yêu thuật trong chuỗi hợp lực thi triển Cổ đạo vô tiên. [CAN-SOAT-GOP]","detail":"Thuật thuộc hệ Yêu. Người thi triển vung tay tạo ngọn lửa xanh biếc (yêu hỏa) trên đầu tu sĩ đã chết, khói hiệu bốc lên hóa thành tám ngọn yên sơn khổng lồ. Yên sơn phát ra lực hút không thể chống cự, cuốn hút hơn mười vạn tu sĩ xung quanh vào trong rồi nuốt chết toàn bộ. Vương Lâm mượn khí thế Diệp Mịch trên đài cao cổ mộ mà thi triển.","nguon":["@c1380","@c1683","@c1733","@c1763","@c1794","@c1836"],"tabs":{},"aliases":["Yêu thuật, phong hỏa thành sơn"]},{"id":"ma-dao-sinh-tu-nghich-dong","name":"Ma đạo — Sinh Tử Nghịch Động","cn":"魔道·生死逆动","loai":"bi-thuat","loaiLabel":"Ma đạo thuật","phamCap":"Đạo cổ thuật","hePhai":"Ma (Cổ Ma tộc)","soHuu":["Đạo cổ Diệp Mịch","Vương Lâm"],"blurb":"Bước thứ ba của Đạo Cổ Vô Tiên, dùng Cổ Ma cửu tinh chuyển hóa sức sống đối phương thành tử khí, đồng thời triệu tử khí từ vô số sinh linh biến thiên địa thành biển chết. (+) Một chỉ điểm ra, sức sống nghịch chuyển thành tử khí, chiến xa ngừng hoạt động, tám con rồng vạn trượng chết đứng, mọi tu sĩ tử vong tức khắc. [CAN-SOAT-GOP] (+) Câu quyết ma đạo trong chuỗi thần, yêu, ma trước cổ đạo vô tiên. [CAN-SOAT-GOP] (+) Thần thông Ma đạo của Vương Lâm kích phát sinh tử nghịch động để sát thương quần thể tu sĩ. [CAN-SOAT-GOP] (+) Một câu quyết ma đạo trong chuỗi thi triển trước khi Cổ đạo vô tiên bộc phát. [CAN-SOAT-GOP]","detail":"Thuật thuộc hệ Ma trong bốn hệ thần-yêu-ma-cổ. Chỉ cần một ngón tay chỉ ra, sinh lực trong phạm vi cực rộng bị nghịch chuyển thành tử khí trong nháy mắt. Chiến xa mất nguồn lực ngừng hoạt động, tám con rồng dài vạn trượng chết đứng giữa không trung, mọi tu sĩ bị chạm tới đều tử vong. Vương Lâm mượn khí thế Diệp Mịch trên đài cao cổ mộ mà thi triển.","nguon":["@c1380","@c1384","@c1683","@c1763","@c1794","@c1836"],"tabs":{}},{"id":"dao-co-thuat-dung-hop-ba-toc","name":"Đạo cổ thuật (dung hợp ba tộc)","cn":"道古术","loai":"than-thong","loaiLabel":"Đạo cổ thuật","phamCap":"Đạo cổ thuật — tối cao","hePhai":"Đạo cổ (Thần + Yêu + Ma dung hợp)","soHuu":["Đạo cổ Diệp Mịch","Vương Lâm"],"blurb":"Sức mạnh Cổ Thần, Cổ Yêu, Cổ Ma dung hợp thành sức mạnh đạo cổ, triệu hồi hư ảnh đầu lâu khổng lồ phun khí tức tang thương biến vạn vật thành đá.","detail":"Khi tinh điểm Cổ Thần trên mi tâm đạt chín (Cửu tinh Cổ Thần), đồng thời trong hai mắt cũng lên mười tám tinh điểm (Cửu tinh Cổ Yêu và Cửu tinh Cổ Ma), sức mạnh ba tộc dung hợp thành sức mạnh đạo cổ. Triệu hồi hư ảnh đầu lâu khổng lồ phun ra khí tức hủy diệt tang thương, biến vạn vật thành đá. Câu kết kèm theo: Thần, yêu, ma, cổ đạo không có tiên. Trong cảnh tượng hư ảo, Diệp Mịch dùng đạo cổ thuật biến nam tử cầm ô và Lý Quảng thành đá, khiến tu sĩ bảy màu phun máu bỏ chạy.","nguon":["@c1380"]},{"id":"that-thai-thuat-nam-tu-cam-o","name":"Thất thải thuật","cn":null,"loai":"than-thong","loaiLabel":"Thuật","phamCap":null,"hePhai":null,"soHuu":["Nam tử cầm ô"],"blurb":"Nam tử cầm ô triển khai ánh sáng bảy màu từ ô, như cầu vồng hóa mặt trời bảy màu chiếu bốn phía, đối kháng đạo cổ thuật.","detail":"Nam tử cầm ô (đệ tử đầu tiên của tu sĩ bảy màu) dùng ô giương lên triển khai ánh sáng bảy màu rực rỡ, tựa cầu vồng hóa thành mặt trời bảy màu chiếu bốn phương, tạo hào quang lóe sáng phá vỡ khí tức tấn công, dùng để đối kháng đạo cổ thuật của Diệp Mịch. Tuy nhiên thuật này cuối cùng bị mũi tên của Lý Quảng xuyên qua và bị khí tức đạo cổ phá tan.","nguon":["@c1380"]},{"id":"tu-hai-huong-hoa","name":"Tử hải hương hỏa","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Linh Động Tộc","soHuu":["Linh Động Thượng Nhân"],"blurb":"Thần thông hồn phách của Linh Động Thượng Nhân, triệu tử hải chứa vô số hồn phách hương hỏa hóa sóng lớn tấn công.","detail":"Linh Động triển khai tử hải ầm ầm tràn ra, bên trong có vô số hồn phách hương hỏa hóa thành sóng lớn tấn công đối thủ. Bị tiếng rống Cổ Thần của Thác Sâm phá vỡ.","congNang":["Triệu hồn phách hương hỏa trong tử hải thành sóng lớn tấn công"],"nguoiTu":[{"ten":"Linh Động Thượng Nhân","tuChuong":"@c1381","tangDatToi":"","trangThai":"dang-dung"}],"tabs":{"tienTrinh":[{"chuong":"@c1381","loai":"thi triển","importance":"normal","giaiDoan":"Linh Động thi triển chống Thác Sâm","text":"Linh Động triển khai tử hải hương hỏa tấn công Thác Sâm, bị tiếng rống Cổ Thần phá vỡ.","anchor":"tử hải ầm ầm tràn ra, bên trong có vô số hồn phách hương hỏa, hóa thành một cơn sóng lớn tràn về phía trước"}]},"nguon":["@c1381"]},{"id":"chieu-huyen-vu-luc-dao","name":"Chiêu Huyền Vũ lực đạo","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Huyền Vũ","soHuu":["Vương Lâm"],"blurb":"Chiêu Huyền Vũ hùng mạnh nhất liên quan lực đạo, do Chu Tước đời thứ hai truyền lại cho Vương Lâm trên Đại Đế Tinh. Chiêu thức này tràn ngập tâm thần Vương Lâm khi hắn đạt cảnh giới thất tinh Cổ Thần.","detail":"Chiêu Huyền Vũ lực đạo là chiêu thức mạnh nhất trong hệ Huyền Vũ mà Vương Lâm cảm ngộ, có liên quan trực tiếp đến lực đạo. Chiêu này được Chu Tước đời thứ hai truyền lại trên Đại Đế Tinh. Khi Vương Lâm đột phá thành thất tinh Cổ Thần, cảm ngộ về chiêu thức này tràn ngập tâm thần hắn. Chi tiết về biểu hiện cụ thể và uy lực thi triển chưa được thể hiện rõ trong tiến trình hiện có.","congNang":["Cảm ngộ lực đạo cực mạnh — chiêu Huyền Vũ hùng mạnh nhất, liên quan lực đạo, tràn ngập tâm thần khi đạt thất tinh Cổ Thần @c1381"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1381","tangDatToi":"","trangThai":"tiep-nhan"}],"tabs":{"tienTrinh":[{"chuong":"@c1381","loai":"xuất hiện","importance":"major","giaiDoan":"Vương Lâm tiếp nhận cảm ngộ khi thành thất tinh","text":"Cảm ngộ chiêu Huyền Vũ hùng mạnh nhất do Chu Tước đời thứ hai truyền lại trên Đại Đế Tinh tràn ngập tâm thần Vương Lâm.","anchor":"chiêu Huyền Vũ hùng mạnh nhất mà Chu Tước đời thứ hai đã truyền lại trên Đại Đế Tinh tràn ngập trong tâm thần hắn"}]},"nguon":["@c1381"]},{"id":"than-thong-truyen-thua-chiec-ghe","name":"Thần thông truyền thừa từ chiếc ghế","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Đạo cổ","soHuu":["Vương Lâm"],"blurb":"Thần thông truyền thừa từ chiếc ghế là những thần thông được truyền trực tiếp vào ký ức Vương Lâm thông qua chiếc ghế, nội dung cụ thể chưa được tiết lộ tính tới mốc hiện có.","detail":"Tại @c1381, chiếc ghế hiện lên những hình ảnh thần thông truyền thừa, phá vỡ thần thức rồi lao thẳng tới Vương Lâm, hóa thành ký ức khắc sâu. Đây là hình thức truyền thừa trực tiếp, bỏ qua quá trình tu luyện thông thường mà đưa thẳng thần thông vào ký ức người nhận. Nội dung cụ thể của các thần thông này chưa được tiết lộ trong tiến trình hiện có.","congNang":["Truyền thần thông trực tiếp vào ký ức người nhận, bỏ qua quá trình lĩnh ngộ thông thường @c1381"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1381","tangDatToi":"","trangThai":"tiep-nhan"}],"tabs":{"tienTrinh":[{"chuong":"@c1381","loai":"xuất hiện","importance":"major","giaiDoan":"Chiếc ghế truyền thần thông vào ký ức Vương Lâm","text":"Chiếc ghế hiện lên hình ảnh thần thông truyền thừa, phá vỡ thần thức lao thẳng tới Vương Lâm, hóa thành ký ức khắc sâu.","anchor":"chiếc ghế còn hiện lên những hình ảnh thần thông truyền thừa! Những thần thông này như phá vỡ thần thức, lao thẳng tới Vương Lâm"}]},"nguon":["@c1381"],"dacDiem":"Thần thông được truyền thừa bằng cách phá vỡ thần thức rồi hóa thành ký ức khắc sâu, là hình thức truyền thừa trực tiếp từ chiếc ghế @c1381"},{"id":"mo-trang-duoi-gieng","name":"Mò trăng dưới giếng","cn":"","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Thái Cổ Tinh Thần","soHuu":["Chưởng Tôn"],"blurb":"Thần thông của Chưởng Tôn Thái Cổ Tinh Thần, bị Vương Lâm nhận ra khi đối đầu qua khe cổ mộ.","detail":"Thần thông được Chưởng Tôn Thái Cổ Tinh Thần sử dụng, có thể liên quan đến cách hắn can thiệp khe cổ mộ từ bên ngoài. Vương Lâm nhận xét thần thông này không tồi.","nguon":["@c1382"],"congNang":["Không rõ cụ thể, có thể liên quan đến can thiệp khe cổ mộ từ bên ngoài"],"nguoiTu":[{"ten":"Chưởng Tôn","tuChuong":"@c1382","tangDatToi":"","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c1382","loai":"xuất hiện","importance":"normal","giaiDoan":"Lần đầu nhắc tên","text":"Vương Lâm nhận ra và nhận xét thần thông Mò trăng dưới giếng của Chưởng Tôn Thái Cổ Tinh Thần khi đối đầu qua khe cổ mộ.","anchor":"Mò trăng dưới giếng, thần thông này quả không tồi"}]}},{"id":"co-ma-tinh","name":"Cổ Ma tinh","cn":"古魔星","loai":"than-thong","loaiLabel":"Thần thông","phamCap":"Không rõ","hePhai":"Cổ Ma","soHuu":["Vương Lâm"],"blurb":"Cổ Ma tinh là hình thái ngưng tụ của ma khí trong mắt phải Vương Lâm, kết thành vòng tròn nhưng chưa hoàn chỉnh do thiếu Cổ Ma lực. Cần phân thân hoàn chỉnh của Cổ Ma mới có thể bổ sung đủ để hoàn thiện.","detail":"Ma khí tích tụ trong mắt phải Vương Lâm tự ngưng tụ thành hình vòng tròn, hình thành nên Cổ Ma tinh. Tuy nhiên, Cổ Ma tinh ở trạng thái chưa hoàn chỉnh do thiếu Cổ Ma lực. Thi thể Cổ Ma thông thường chỉ tàn dư chút khí tức, không đủ để bổ sung; duy có phân thân hoàn chỉnh của Cổ Ma mới cung cấp đủ lực lượng cần thiết để hoàn thiện Cổ Ma tinh. Lần đầu được đề cập tại @c1383.","congNang":["Ngưng tụ ma tinh bổ trợ tu luyện hệ Cổ Ma @c1383"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1383","tangDatToi":"Chưa hoàn chỉnh","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1383","loai":"xuất hiện","importance":"major","giaiDoan":"Lần đầu lộ diện, chưa hoàn chỉnh","text":"Ma khí trong mắt phải Vương Lâm ngưng tụ thành vòng tròn hình thành Cổ Ma tinh nhưng chưa hoàn chỉnh vì thiếu Cổ Ma lực. Vương Lâm dùng pho tượng thi thể Cổ Ma cao ngàn trượng để bổ sung nhưng thi thể chỉ có chút khí tức, không đủ.","anchor":"trong mắt phải của hắn còn có ma khí tạo thành vòng tròn, ngưng tụ thành cổ Ma tinh"}]},"nguon":["@c1383"],"dacDiem":"Ma khí trong mắt phải ngưng tụ thành vòng tròn; ở trạng thái chưa hoàn chỉnh, cần Cổ Ma lực từ phân thân hoàn chỉnh của Cổ Ma để hoàn thiện."},{"id":"chin-muoi-chin-quyen-dung-thanh-mot","name":"Chín mươi chín quyền dung thành một","cn":"","loai":"bi-thuat","loaiLabel":"Chiến pháp","phamCap":"","hePhai":"Cổ Thần","soHuu":["Thác Sâm"],"blurb":"Chiến pháp của Thác Sâm theo đạo dĩ lực phá thiên — một quyền giáng xuống thực chất là chín mươi chín quyền tốc độ cực nhanh dung hợp, thuần túy áp đảo bằng sức mạnh.","detail":"Đạo của Thác Sâm là dĩ lực phá thiên, không dùng kỹ xảo. Khi thi triển, hắn vung ra chín mươi chín quyền trong nháy mắt với tốc độ cực nhanh, dung hợp tất cả thành một quyền duy nhất. Nhìn bên ngoài chỉ thấy một quyền giáng xuống, nhưng thực chất chứa uy lực gộp của chín mươi chín quyền. Chiến pháp này thể hiện triết lý chiến đấu thuần lực áp đảo, phù hợp với sức mạnh thân thể Cổ Thần đỉnh bát tinh mà Thác Sâm (trong thân Đồ Ti) sở hữu.","nguon":["@c1384"]},{"id":"dao-co-truyen-thua","name":"Đạo Cổ truyền thừa","cn":"","loai":"khac","loaiLabel":"Truyền thừa / Ký ức","phamCap":"Không rõ","hePhai":"Đạo Cổ","soHuu":["Vương Lâm"],"blurb":"Đạo Cổ truyền thừa là phần ký ức truyền thừa duy nhất mà Vương Lâm thu được từ tầng nhất cổ mộ Đạo Cổ, nhờ đó hiểu rõ cấu trúc tầng nhất cổ mộ và nắm được cách mở Địa Phù ẩn trong bản đồ thứ chín. (+) Nguồn gốc của Cổ Thần, vượt trên Cổ Thần/Cổ Yêu/Cổ Ma. Vương Lâm sở hữu Đạo Cổ truyền thừa. [CAN-SOAT-GOP]","detail":"Trong cổ mộ Đạo Cổ, Vương Lâm đã lấy được một phần ký ức truyền thừa tại tầng nhất. Phần truyền thừa này mang tính duy nhất — ngoài Vương Lâm ra không ai có thể tiếp tục thu được. Nhờ phần ký ức này, hắn hiểu rõ cấu trúc tầng nhất cổ mộ Đạo Cổ hơn bất kỳ ai khác và biết cách mở Địa Phù ẩn giấu bên trong bản đồ thứ chín. Hắn tuyên bố khi tu vi đủ cao sẽ quay lại tiếp tục truyền thừa.","thuocTinh":"Đạo Cổ","nguonGoc":"Cổ mộ Đạo Cổ, tầng nhất","dacDiem":"Duy nhất, không ai ngoài Vương Lâm có thể tiếp tục có được","congNang":["Hiểu rõ cấu trúc tầng nhất cổ mộ Đạo Cổ @c1386","Biết cách mở Địa Phù ẩn trong bản đồ thứ chín @c1386"],"nguoiTu":[{"ten":"Vương Lâm","tuChuong":"@c1386","tangDatToi":"Một phần","trangThai":"dang-tu"}],"tabs":{"tienTrinh":[{"chuong":"@c1386","loai":"xuất hiện","importance":"major","giaiDoan":"Vương Lâm lấy được ký ức Đạo Cổ duy nhất","text":"Vương Lâm lấy được một phần ký ức Đạo Cổ truyền thừa duy nhất, dùng nó mở Địa Phù trong bản đồ thứ chín. Tuyên bố sẽ quay lại nếu tu vi đủ.","anchor":"truyền thừa này là duy nhất, ngoài hắn ra, không người nào có thể tiếp tục có được"}]},"nguon":["@c1386","@c1392"]},{"id":"an-ky-mo-tang-co-mo-thu-hai","name":"Ấn ký mở tầng cổ mộ thứ hai","cn":"","loai":"bi-thuat","loaiLabel":"Ấn ký","phamCap":"Không rõ","hePhai":"Đạo Cổ","soHuu":["Vương Lâm"],"blurb":"Ấn ký được Vương Lâm đánh lên bầu trời tại tầng nhất cổ mộ, kích hoạt biển sương mù chứa vô số chiến hồn bên dưới chín tấm bản đồ, từ đó mở ra tầng cổ mộ thứ hai. Hắn dùng tầng hai này như lễ vật dành cho các tu sĩ sống sót.","detail":"Tại tầng nhất cổ mộ, Vương Lâm đánh một ấn ký lên bầu trời để kích hoạt biển sương mù nằm bên dưới chín tấm bản đồ. Bên trong sương mù ấy tồn tại vô số chiến hồn. Ấn ký mở ra tầng cổ mộ thứ hai, và Vương Lâm sử dụng tầng hai chứa chiến hồn này làm lễ vật ban cho các tu sĩ còn sống sót.","congNang":["Kích hoạt biển sương mù chứa vô số chiến hồn bên dưới chín tấm bản đồ tại tầng nhất cổ mộ @c1386","Mở ra tầng cổ mộ thứ hai, dùng làm lễ vật cho các tu sĩ sống sót @c1386"],"tabs":{"tienTrinh":[{"chuong":"@c1386","loai":"thi triển","importance":"major","giaiDoan":"Vương Lâm đánh ấn ký mở tầng hai","text":"Vương Lâm đánh ấn ký mở ra tầng cổ mộ thứ hai chứa vô số chiến hồn, làm lễ vật cho tu sĩ sống sót.","anchor":"Một ấn ký này của Vương Lâm chính là ấn ký để mở ra tầng cổ mộ thứ hai"}]},"nguon":["@c1386"]}]};